window.XSINO_DATA = {"meta":{"brand":"XSINO","tagline_en":"Where the next decision changes everything","tagline_es":"Donde la próxima decisión lo cambia todo","thesis_en":"Luck begins with the next decision.","thesis_es":"La suerte empieza en la próxima decisión.","market_en":"Online casino — Mexico & Latin America","market_es":"Casino en línea — México y Latinoamérica","format_en":"Vertical 9:16 · 15–40s","format_es":"Vertical 9:16 · 15–40s","brands":[{"key":"xsino","name":"XSINO","tone_en":"Cyberpunk casino — Mexico & LatAm; neon purple/pink/cyan, gold for the luck-moment","tone_es":"Casino cyberpunk — México y LatAm; neón morado/rosa/cian, oro para el momento de suerte"},{"key":"heaven","name":"HeavenOnline","tone_en":"Sibling brand — celestial luxury, black + gold + white, warm & romantic","tone_es":"Marca hermana — lujo celestial, negro + oro + blanco, cálida y romántica"}]},"pillars":[{"key":"inspire","es":"Historias que Inspiran","en":"Stories That Inspire","accent":"#D9A441","accent2":"#E8C87A","icon":"✦","pairs":[{"es":"Esperanza y resiliencia. Gente común que persevera y se transforma; el momento en que una decisión pequeña reescribe una vida.","en":"Hope and resilience. Ordinary people who persevere and transform; the moment a small decision rewrites a life.","proposal":false},{"es":"Historias base: \"La Moneda del Destino\" y \"El Abuelo y su Nieta\".","en":"Anchor stories: \"The Coin of Destiny\" and \"The Grandfather and His Granddaughter.\"","proposal":false},{"es":"Formato: realismo cinematográfico cálido, 30–60s, con una congelación de tiempo en el instante de la decisión.","en":"Format: warm cinematic realism, 30–60s, with a time-freeze on the instant of the decision.","proposal":false}]},{"key":"love","es":"Amores Imposibles","en":"Impossible Love Stories","accent":"#4C8C86","accent2":"#E0A46A","icon":"♥","pairs":[{"es":"Romance y destino. Contenido pensado para alcanzar audiencias fuera del segmento de casino o gaming.","en":"Romance and fate. Content designed to reach audiences beyond the casino or gaming segment.","proposal":false},{"es":"Historia base: \"Dos Extraños\" — montaje paralelo: la misma canción, el mismo color, el mismo café, y un cruce final.","en":"Anchor story: \"Two Strangers\" — parallel editing: the same song, the same color, the same coffee, and a final crossing.","proposal":false},{"es":"Formato: romance fílmico, pantalla dividida o corte paralelo, paleta compartida ámbar y verde-azulado.","en":"Format: filmic romance, split-screen or parallel cut, a shared amber-and-teal palette.","proposal":false}]},{"key":"anime","es":"Universo Anime XSINO","en":"XSINO Anime Universe","accent":"#E24D9C","accent2":"#34C6E0","icon":"◈","pairs":[{"es":"Aventura fantástica que conecta las mecánicas del juego —niveles, puertas VIP, retos, recompensas— con un mundo de ficción reconocible.","en":"Fantasy adventure connecting the game's mechanics — levels, VIP gates, challenges, rewards — to a recognizable fictional world.","proposal":false},{"es":"Historia base: \"La Rueda del Destino\" (shonen). El universo visual más escalable y el vínculo más fuerte con el producto.","en":"Anchor story: \"The Wheel of Destiny\" (shonen). The most scalable visual universe and the strongest tie to the product.","proposal":false},{"es":"Formato: anime shonen + cyberpunk, neón sobre negro, la Rueda del Destino como coloso giratorio; niveles VIP recurrentes.","en":"Format: shonen anime + cyberpunk, neon over black, the Wheel of Destiny as a spinning colossus; recurring VIP levels.","proposal":false}]},{"key":"whatif","es":"¿Y Si...?","en":"What If...?","accent":"#E8B84B","accent2":"#F6D98A","icon":"?","pairs":[{"es":"Curiosidad de giro rápido. Episodios repetibles de menos de 30 segundos, guiados por voz en off, fáciles de convertir en serie.","en":"Quick-twist curiosity. Repeatable episodes under 30 seconds, voiceover-driven, easy to turn into a series.","proposal":false},{"es":"Historia base: \"¿Y Si la Suerte Tuviera Voz?\" — la Suerte personificada habla al espectador y le propone una elección.","en":"Anchor story: \"What If Luck Had a Voice?\" — Luck personified speaks to the viewer and offers a choice.","proposal":false},{"es":"Formato: gráfico y minimalista, alto contraste, oro sobre negro; termina en pregunta directa a la cámara para provocar comentarios.","en":"Format: graphic and minimal, high contrast, gold over black; ends on a direct question to camera to drive comments.","proposal":false}]}],"characters":[{"id":"01","name":"Mateo Rivas","pillar":"inspire","priority":"T0","color":"#3B5A78","color2":"#D9A441","alias_es":"El Mecánico","alias_en":"The Mechanic","sections":[{"es":"Datos Básicos","en":"Basic Information","pairs":[{"es":"Nombre: Mateo Rivas. Edad: 34. Pilar: Historias que Inspiran. Protagonista de \"La Moneda del Destino\".","en":"Name: Mateo Rivas. Age: 34. Pillar: Stories That Inspire. Protagonist of \"The Coin of Destiny.\"","proposal":false},{"es":"Oficio: obrero de fábrica en una ciudad latinoamericana; el último en salir cada turno.","en":"Occupation: factory worker in a Latin American city; the last to leave every shift.","proposal":false},{"es":"Deseo secreto: una entrevista de trabajo que lleva semanas evitando por miedo.","en":"Secret want: a job interview he has been avoiding for weeks out of fear.","proposal":false}]},{"es":"Apariencia y Diseño Visual","en":"Appearance & Visual Design","pairs":[{"es":"Complexión trabajada, hombros cansados. Ropa de trabajo gastada, chaqueta azul obrero desteñida.","en":"A worked, lean build, tired shoulders. Worn work clothes, a faded worker-blue jacket.","proposal":false},{"es":"Rostro amable marcado por el cansancio; barba de dos días; manos ásperas.","en":"A kind face marked by fatigue; two-day stubble; rough hands.","proposal":false},{"es":"Paleta: azul obrero, gris ceniza; el oro solo aparece en la moneda, en el instante de la decisión.","en":"Palette: worker blue, ash grey; gold appears only on the coin, at the instant of the decision.","proposal":false}]},{"es":"Temperamento y Personalidad","en":"Temperament & Personality","pairs":[{"es":"Resignado por fuera, valiente por dentro. Su lucha no es contra el mundo, sino contra su propia postergación.","en":"Resigned on the outside, brave underneath. His fight is not against the world, but against his own procrastination.","proposal":false},{"es":"Tiende a dejar que \"la suerte\" decida para no cargar con el peso de elegir. Su arco es dejar de hacerlo.","en":"He tends to let \"luck\" decide so he doesn't carry the weight of choosing. His arc is to stop doing that.","proposal":false}]},{"es":"Rol en la Historia","en":"Role in the Story","pairs":[{"es":"Encarna la tesis de marca: la suerte empieza en la próxima decisión. Atrapa la moneda en el aire en vez de dejarla caer.","en":"He embodies the brand thesis: luck begins with the next decision. He catches the coin mid-air instead of letting it fall.","proposal":false},{"es":"Su historia es el arquetipo del pilar: realismo cálido, un solo momento, un solo giro emocional.","en":"His story is the pillar's archetype: warm realism, a single moment, a single emotional turn.","proposal":false}]},{"es":"Frases Clave","en":"Key Lines","pairs":[{"es":"\"Es más fácil culpar a la suerte que cargar con la decisión.\"","en":"\"It's easier to blame luck than to carry the decision.\"","proposal":false},{"es":"\"Esta vez, no.\"","en":"\"Not this time.\"","proposal":false}]},{"es":"Ficha de Diseño (para keyframes)","en":"Design-Sheet Notes (for keyframes)","pairs":[{"es":"Vistas: frente (cuerpo completo, casco en mano), perfil, espalda saliendo de la fábrica, expresión (duda→decisión), acción (atrapando la moneda). Realismo cinematográfico, hora nocturna, grano suave.","en":"Views: front (full body, helmet in hand), profile, back leaving the factory, expression (doubt→decision), action (catching the coin). Cinematic realism, night hour, soft grain.","proposal":false}]}]},{"id":"02","name":"Don Emilio","pillar":"inspire","priority":"T1","color":"#6B4A2E","color2":"#C8A24B","alias_es":"El Abuelo","alias_en":"The Grandfather","sections":[{"es":"Datos Básicos","en":"Basic Information","pairs":[{"es":"Nombre: Don Emilio. Edad: 72. Pilar: Historias que Inspiran. Personaje central de \"El Abuelo y su Nieta\".","en":"Name: Don Emilio. Age: 72. Pillar: Stories That Inspire. Central character of \"The Grandfather and His Granddaughter.\"","proposal":false},{"es":"Oficio: jubilado; pasó cuarenta años como zapatero de barrio. Ahora su oficio es cuidar a su nieta.","en":"Occupation: retired; he spent forty years as a neighborhood shoemaker. Now his occupation is caring for his granddaughter.","proposal":false},{"es":"Deseo secreto: volver a ver el mar una vez más, un viaje que siempre pospuso por falta de dinero.","en":"Secret want: to see the ocean once more, a trip he always postponed for lack of money.","proposal":true}]},{"es":"Apariencia y Diseño Visual","en":"Appearance & Visual Design","pairs":[{"es":"Complexión menuda y encorvada por los años; manos nudosas que aún tiemblan un poco al coser un botón.","en":"A small frame, stooped by the years; knotty hands that still tremble a little when sewing on a button.","proposal":false},{"es":"Suéter de lana café desgastado en los codos, boina calada, lentes de armazón grueso heredados de otra época.","en":"A worn brown wool sweater, thin at the elbows, a flat cap pulled low, thick-framed glasses inherited from another era.","proposal":false},{"es":"Paleta: sepia y marrón cálido; el oro desteñido aparece solo en el marco de una foto vieja sobre la mesa.","en":"Palette: sepia and warm brown; faded gold appears only in the frame of an old photo on the table.","proposal":false}]},{"es":"Temperamento y Personalidad","en":"Temperament & Personality","pairs":[{"es":"Paciente hasta la exageración; su voz nunca sube de tono, ni cuando Lucía rompe algo por accidente.","en":"Patient to a fault; his voice never rises, not even when Lucía breaks something by accident.","proposal":false},{"es":"Guarda su dolor con dignidad silenciosa; sonríe primero y llora después, cuando ella ya se durmió.","en":"He carries his pain with quiet dignity; he smiles first and cries later, once she has fallen asleep.","proposal":false}]},{"es":"Rol en la Historia","en":"Role in the Story","pairs":[{"es":"Encarna la tesis del pilar desde el otro extremo de la vida: la suerte que ya vivió no fue un premio, fue su familia.","en":"He embodies the pillar's thesis from the other end of life: the luck he already lived was not a prize, it was his family.","proposal":false},{"es":"Su relación con Lucía es la prueba viva de la tesis de marca: la suerte no es un resultado, es a quién tienes al lado cuando decides seguir.","en":"His bond with Lucía is the living proof of the brand thesis: luck is not an outcome, it's who stands beside you when you decide to keep going.","proposal":false},{"es":"Su arco cierra \"El Abuelo y su Nieta\": elige gastar sus únicos ahorros en el cumpleaños de Lucía, no en boletos de la suerte.","en":"His arc closes \"The Grandfather and His Granddaughter\": he chooses to spend his only savings on Lucía's birthday, not on a lucky ticket.","proposal":true}]},{"es":"Frases Clave","en":"Key Lines","pairs":[{"es":"\"La suerte más grande que tuve ya está dormida en el cuarto de al lado.\"","en":"\"The greatest luck I ever had is already asleep in the next room.\"","proposal":false},{"es":"\"No necesito ganar nada más, hijo. Ya gané lo que importaba.\"","en":"\"I don't need to win anything else, son. I already won what mattered.\"","proposal":false}]},{"es":"Ficha de Diseño (para keyframes)","en":"Design-Sheet Notes (for keyframes)","pairs":[{"es":"Vistas: frente (sentado en su silla de siempre, remendando), perfil leyendo bajo lámpara amarilla, espalda mirando por la ventana, expresión (nostalgia→ternura), acción (abrazando a Lucía). Realismo cálido, luz de tarde, grano de película suave.","en":"Views: front (seated in his usual chair, mending), profile reading under a yellow lamp, back looking out the window, expression (nostalgia→tenderness), action (hugging Lucía). Warm realism, late-afternoon light, soft film grain.","proposal":false}]}]},{"id":"03","name":"Lucía","pillar":"inspire","priority":"T1","color":"#B98A5E","color2":"#E8C87A","alias_es":"La Nieta","alias_en":"The Granddaughter","sections":[{"es":"Datos Básicos","en":"Basic Information","pairs":[{"es":"Nombre: Lucía. Edad: 8. Pilar: Historias que Inspiran. Coprotagonista de \"El Abuelo y su Nieta\".","en":"Name: Lucía. Age: 8. Pillar: Stories That Inspire. Co-protagonist of \"The Grandfather and His Granddaughter.\"","proposal":false},{"es":"Vive con su abuelo, Don Emilio, en un departamento pequeño de un barrio popular.","en":"She lives with her grandfather, Don Emilio, in a small apartment in a working-class neighborhood.","proposal":false},{"es":"Deseo secreto: que su abuelo deje de preocuparse por el dinero y solo juegue con ella, como antes.","en":"Secret want: for her grandfather to stop worrying about money and just play with her, like before.","proposal":true}]},{"es":"Apariencia y Diseño Visual","en":"Appearance & Visual Design","pairs":[{"es":"Complexión pequeña y ágil, siempre en movimiento; rodillas raspadas de tanto correr en el patio.","en":"A small, quick build, always in motion; knees scraped from running in the courtyard.","proposal":false},{"es":"Vestido de algodón color crema heredado de una prima, un listón dorado desgastado atado en la trenza.","en":"A cream cotton dress handed down from a cousin, a worn gold ribbon tied into her braid.","proposal":false},{"es":"Guarda piedritas de colores en los bolsillos del vestido, sus \"monedas de la suerte\" imaginarias.","en":"She keeps colored pebbles in her dress pockets, her imaginary \"luck coins.\"","proposal":false},{"es":"Paleta: crema suave y los tonos tierra de la casa de su abuelo; el único dorado vive en su listón.","en":"Palette: soft cream and the earth tones of her grandfather's home; the only gold lives in her ribbon.","proposal":false}]},{"es":"Temperamento y Personalidad","en":"Temperament & Personality","pairs":[{"es":"Curiosa hasta el extremo; hace preguntas que Don Emilio no siempre sabe responder, y eso la hace reír más.","en":"Curious to a fault; she asks questions Don Emilio doesn't always know how to answer, which makes her laugh even more.","proposal":false},{"es":"Percibe la tristeza de los adultos antes que ellos la nombren, y responde con un abrazo, no con palabras.","en":"She senses adults' sadness before they name it, and answers with a hug, not with words.","proposal":false}]},{"es":"Rol en la Historia","en":"Role in the Story","pairs":[{"es":"Es el corazón tierno del pilar: no sabe nada de suerte ni de dinero, y por eso ve con más claridad lo que de verdad importa.","en":"She is the pillar's tender heart: she knows nothing of luck or money, and so she sees most clearly what truly matters.","proposal":false},{"es":"Su cumpleaños es el giro emocional de la historia: el regalo que recibe no cuesta nada y lo es todo.","en":"Her birthday is the story's emotional turn: the gift she receives costs nothing and is everything.","proposal":true}]},{"es":"Frases Clave","en":"Key Lines","pairs":[{"es":"\"Abuelo, ¿la suerte se puede compartir, como el pan?\"","en":"\"Grandpa, can luck be shared, like bread?\"","proposal":false},{"es":"\"Yo ya gané mi premio. Eres tú.\"","en":"\"I already won my prize. It's you.\"","proposal":false}]},{"es":"Ficha de Diseño (para keyframes)","en":"Design-Sheet Notes (for keyframes)","pairs":[{"es":"Vistas: frente (de pie con su listón dorado, sonriendo), perfil corriendo en el patio, espalda tomada de la mano de su abuelo, expresión (curiosidad→alegría), acción (soplando las velitas de su pastel). Realismo cálido, luz dorada de tarde, foco suave en su rostro.","en":"Views: front (standing with her gold ribbon, smiling), profile running in the courtyard, back holding her grandfather's hand, expression (curiosity→joy), action (blowing out her birthday candles). Warm realism, golden afternoon light, soft focus on her face.","proposal":false}]}]},{"id":"04","name":"Valentina Cruz","pillar":"love","priority":"T2","color":"#4C8C86","color2":"#EDE6D4","alias_es":"Extraña A","alias_en":"Stranger A","sections":[{"es":"Datos Básicos","en":"Basic Information","pairs":[{"es":"Nombre: Valentina Cruz. Edad: 29. Pilar: Amores Imposibles. Protagonista A de \"Dos Extraños\".","en":"Name: Valentina Cruz. Age: 29. Pillar: Impossible Love Stories. Protagonist A of \"Two Strangers.\"","proposal":false},{"es":"Oficio: ilustradora freelance; trabaja desde la misma mesa de la misma cafetería cada mañana.","en":"Occupation: freelance illustrator; she works from the same table at the same café every morning.","proposal":false},{"es":"Deseo secreto: dejar de vivir en piloto automático y notar, por una vez, lo que tiene enfrente.","en":"Secret want: to stop living on autopilot and notice, for once, what is right in front of her.","proposal":true}]},{"es":"Apariencia y Diseño Visual","en":"Appearance & Visual Design","pairs":[{"es":"Complexión esbelta, con la postura de quien dibuja todo el día encorvada sobre un cuaderno.","en":"A slim build, with the posture of someone who draws all day hunched over a notebook.","proposal":false},{"es":"Abrigo verde-azulado entallado, audífonos siempre puestos, un cuaderno de tapa gastada bajo el brazo.","en":"A fitted teal coat, headphones always on, a worn-cover notebook tucked under her arm.","proposal":false},{"es":"Paleta: verde-azulado #4C8C86 y marfil; la luz de ventana la baña en tonos fríos hasta el instante del cruce.","en":"Palette: teal #4C8C86 and ivory; window light bathes her in cool tones until the instant of the crossing.","proposal":false}]},{"es":"Temperamento y Personalidad","en":"Temperament & Personality","pairs":[{"es":"Observadora y reservada; nota los detalles del mundo antes que a las personas dentro de él.","en":"Observant and reserved; she notices the details of the world before the people inside it.","proposal":false},{"es":"Se protege con la rutina —la misma canción, el mismo café— porque el cambio siempre le costó caro.","en":"She protects herself with routine — the same song, the same coffee — because change has always cost her dearly.","proposal":false}]},{"es":"Rol en la Historia","en":"Role in the Story","pairs":[{"es":"Vive en paralelo a Andrés durante toda la pieza: misma canción, mismo café, mismo minuto, sin saber que él existe.","en":"She lives in parallel to Andrés through the whole piece: same song, same coffee, same minute, without knowing he exists.","proposal":false},{"es":"Su arco se resuelve solo en el cruce final, cuando el montaje paralelo se convierte en un mismo encuadre.","en":"Her arc resolves only at the final crossing, when the parallel edit becomes a single shared frame.","proposal":false},{"es":"El hilo de luz dorada que conecta a los amantes aparece primero en su cuaderno, como si ya lo hubiera dibujado sin saberlo.","en":"The thread of golden light connecting the lovers first appears in her notebook, as if she had already drawn it without knowing.","proposal":true}]},{"es":"Frases Clave","en":"Key Lines","pairs":[{"es":"\"Hoy se siente distinto, aunque todo sea igual que ayer.\"","en":"\"Today feels different, even though everything is the same as yesterday.\"","proposal":false},{"es":"\"Llevo meses dibujando a alguien que nunca he visto.\"","en":"\"I've spent months drawing someone I've never seen.\"","proposal":false}]},{"es":"Ficha de Diseño (para keyframes)","en":"Design-Sheet Notes (for keyframes)","pairs":[{"es":"Vistas: frente (sentada en la mesa de la cafetería, cuaderno abierto), perfil mirando por la ventana, espalda caminando bajo la lluvia, expresión (rutina→sorpresa), acción (levantando la vista en el cruce). Romance fílmico, luz de ventana fría, encuadre que espeja el de Andrés.","en":"Views: front (seated at the café table, notebook open), profile looking out the window, back walking in the rain, expression (routine→surprise), action (looking up at the crossing). Filmic romance, cool window light, framing that mirrors Andrés's.","proposal":false}]}]},{"id":"05","name":"Andrés Molina","pillar":"love","priority":"T2","color":"#E0A46A","color2":"#2E2A2A","alias_es":"Extraño B","alias_en":"Stranger B","sections":[{"es":"Datos Básicos","en":"Basic Information","pairs":[{"es":"Nombre: Andrés Molina. Edad: 31. Pilar: Amores Imposibles. Protagonista B de \"Dos Extraños\".","en":"Name: Andrés Molina. Age: 31. Pillar: Impossible Love Stories. Protagonist B of \"Two Strangers.\"","proposal":false},{"es":"Oficio: barista y músico a medio tiempo; conoce la carta de memoria pero nunca ha tocado su propia canción para nadie.","en":"Occupation: barista and part-time musician; he knows the menu by heart but has never played his own song for anyone.","proposal":false},{"es":"Deseo secreto: que alguien note la canción que tararea, no solo el café que sirve.","en":"Secret want: for someone to notice the song he hums, not just the coffee he serves.","proposal":true}]},{"es":"Apariencia y Diseño Visual","en":"Appearance & Visual Design","pairs":[{"es":"Complexión relajada, manos seguras de tanto servir tazas calientes toda la mañana.","en":"A relaxed build, hands made steady from serving hot cups all morning.","proposal":false},{"es":"Chaqueta color ámbar sobre camisa gris carbón, mangas siempre remangadas, un lápiz detrás de la oreja.","en":"An amber jacket over a charcoal-grey shirt, sleeves always rolled up, a pencil behind his ear.","proposal":false},{"es":"Paleta: ámbar #E0A46A y gris carbón; la luz cálida de la máquina de café lo enmarca hasta el cruce final.","en":"Palette: amber #E0A46A and charcoal; the espresso machine's warm light frames him until the final crossing.","proposal":false}]},{"es":"Temperamento y Personalidad","en":"Temperament & Personality","pairs":[{"es":"Cálido y bromista con los clientes, pero guarda su verdadera voz para cuando nadie escucha.","en":"Warm and easygoing with customers, but he saves his true voice for when no one is listening.","proposal":false},{"es":"Cree en las señales pequeñas —una canción repetida, un cliente que nunca llega— más de lo que admite.","en":"He believes in small signs — a repeated song, a customer who never arrives — more than he admits.","proposal":false}]},{"es":"Rol en la Historia","en":"Role in the Story","pairs":[{"es":"Vive en paralelo a Valentina: prepara el mismo café, tararea la misma canción, sin saber que ella existe a unas cuadras.","en":"He lives in parallel to Valentina: he makes the same coffee, hums the same song, without knowing she exists a few blocks away.","proposal":false},{"es":"Su arco se resuelve en el mismo instante que el de ella: el montaje paralelo colapsa en un solo encuadre compartido.","en":"His arc resolves in the same instant as hers: the parallel edit collapses into one shared frame.","proposal":false},{"es":"El hilo de luz dorada aparece primero en las notas que tararea, como si ya conociera una melodía que nunca escribió.","en":"The thread of golden light first appears in the notes he hums, as if he already knew a melody he never wrote.","proposal":true}]},{"es":"Frases Clave","en":"Key Lines","pairs":[{"es":"\"Sirvo cien cafés al día y ninguno sabe a lo que busco.\"","en":"\"I serve a hundred coffees a day, and none of them taste like what I'm looking for.\"","proposal":false},{"es":"\"Esta canción no es mía. Pero siento que la escribí para alguien.\"","en":"\"This song isn't mine. But I feel like I wrote it for someone.\"","proposal":false}]},{"es":"Ficha de Diseño (para keyframes)","en":"Design-Sheet Notes (for keyframes)","pairs":[{"es":"Vistas: frente (detrás de la barra, preparando café), perfil tarareando junto a la máquina, espalda cerrando la cafetería de noche, expresión (rutina→asombro), acción (deteniéndose al escuchar la canción cruzar la calle). Romance fílmico, luz cálida de barra, encuadre que espeja el de Valentina.","en":"Views: front (behind the counter, making coffee), profile humming beside the machine, back closing the café at night, expression (routine→wonder), action (stopping as he hears the song cross the street). Filmic romance, warm counter light, framing that mirrors Valentina's.","proposal":false}]}]},{"id":"06","name":"Kairo","pillar":"anime","priority":"T1","color":"#34C6E0","color2":"#E8B84B","alias_es":"El Girador","alias_en":"The Spinner","sections":[{"es":"Datos Básicos","en":"Basic Information","pairs":[{"es":"Nombre: Kairo. Edad aparente: 19. Pilar: Universo Anime XSINO. Protagonista de \"La Rueda del Destino\".","en":"Name: Kairo. Apparent age: 19. Pillar: XSINO Anime Universe. Protagonist of \"The Wheel of Destiny.\"","proposal":false},{"es":"Rol: el Girador; avatar del jugador dentro del universo anime, sube las seis puertas VIP hacia la Rueda.","en":"Role: the Spinner; the player's avatar inside the anime universe, climbing the six VIP gates toward the Wheel.","proposal":false},{"es":"Origen: nadie recuerda su llegada a la ciudad-casino; solo que apareció con una moneda que nunca deja de girar.","en":"Origin: no one remembers his arrival in the casino-city; only that he appeared carrying a coin that never stops spinning.","proposal":true}]},{"es":"Apariencia y Diseño Visual","en":"Appearance & Visual Design","pairs":[{"es":"Complexión ágil y atlética, de shonen clásico; cicatriz pequeña sobre la ceja izquierda de una puerta anterior.","en":"A lean, athletic build, classic shonen proportions; a small scar over his left brow from an earlier gate.","proposal":false},{"es":"Chaqueta negra con vivos cian, guantes dorados desgastados por el uso, cabello alborotado con mechones cian en las puntas.","en":"A black jacket trimmed in cyan, gold gloves worn thin from use, spiky hair tipped with streaks of cyan.","proposal":false},{"es":"Paleta: dorado y neón cian sobre negro; el oro se enciende en sus manos solo cuando cruza una puerta.","en":"Palette: gold and cyan neon over black; the gold ignites in his hands only when he clears a gate.","proposal":false}]},{"es":"Temperamento y Personalidad","en":"Temperament & Personality","pairs":[{"es":"Terco hasta la obstinación; pierde en cinco puertas y vuelve a intentarlo en la sexta sin dudar.","en":"Stubborn to the point of obstinacy; he loses at five gates and tries the sixth without hesitating.","proposal":false},{"es":"No pelea por el premio final, sino por demostrarse a sí mismo que esta vez no se va a rendir.","en":"He doesn't fight for the final prize, but to prove to himself that this time he will not quit.","proposal":false},{"es":"Bromea para ocultar el miedo; su humor sube justo cuando la puerta que enfrenta es la más difícil.","en":"He jokes to hide his fear; his humor spikes exactly when the gate ahead is the hardest.","proposal":false}]},{"es":"Rol en la Historia","en":"Role in the Story","pairs":[{"es":"Encarna la mecánica del producto convertida en mito: cada puerta VIP es un nivel real de recompensa, dramatizado como un reto shonen.","en":"He embodies the product's mechanic turned myth: each VIP gate is a real reward tier, dramatized as a shonen trial.","proposal":false},{"es":"Su arco es ascender las seis puertas hasta enfrentar a Nyx en la última y ganarse el examen final de Vega ante la Rueda.","en":"His arc is to climb the six gates, face Nyx at the last one, and earn Vega's final trial before the Wheel.","proposal":false}]},{"es":"Frases Clave","en":"Key Lines","pairs":[{"es":"\"No necesito que la Rueda me sonría. Solo necesito una puerta más.\"","en":"\"I don't need the Wheel to smile at me. I just need one more gate.\"","proposal":false},{"es":"\"Cada puerta que pierdo me enseña cómo ganar la siguiente.\"","en":"\"Every gate I lose teaches me how to win the next one.\"","proposal":false}]},{"es":"Ficha de Diseño (para keyframes)","en":"Design-Sheet Notes (for keyframes)","pairs":[{"es":"Vistas: frente (de pie ante una puerta VIP iluminada, guantes brillando), perfil corriendo hacia la puerta, espalda con la ciudad-casino neón detrás, expresión (duda→determinación), acción (golpeando la puerta con el puño dorado). Shonen-cyberpunk, neón cian y negro, destello dorado solo en el impacto.","en":"Views: front (standing before a lit VIP gate, gloves glowing), profile running toward the gate, back with the neon casino-city behind him, expression (doubt→determination), action (striking the gate with his gold-lit fist). Shonen-cyberpunk, cyan neon over black, gold flash only on impact.","proposal":false}]}]},{"id":"07","name":"Vega","pillar":"anime","priority":"T2","color":"#7A4FA0","color2":"#E8B84B","alias_es":"El Guardián de la Rueda","alias_en":"The Wheel Keeper","sections":[{"es":"Datos Básicos","en":"Basic Information","pairs":[{"es":"Nombre: Vega. Edad aparente: intemporal. Pilar: Universo Anime XSINO. Guardiana-mentora de la Rueda del Destino en \"La Rueda del Destino\".","en":"Name: Vega. Apparent age: timeless. Pillar: XSINO Anime Universe. Guardian-mentor of the Wheel of Destiny in \"The Wheel of Destiny.\"","proposal":false},{"es":"Rol: custodia el santuario donde gira la Rueda y decide quién merece hacerla girar por sí mismo.","en":"Role: she keeps the sanctuary where the Wheel spins and decides who is worthy to turn it themselves.","proposal":false},{"es":"Se dice que Vega fue la primera Giradora, hace tantos ciclos que ya nadie lo recuerda salvo ella.","en":"It is said Vega was the very first Spinner, so many cycles ago that no one remembers except her.","proposal":true}]},{"es":"Apariencia y Diseño Visual","en":"Appearance & Visual Design","pairs":[{"es":"Complexión alta y serena, con porte de estatua que respira; se mueve como si el tiempo no la alcanzara.","en":"A tall, serene build, the bearing of a statue that breathes; she moves as if time never catches up to her.","proposal":false},{"es":"Túnica violeta profundo bordada en hilo dorado, máscara parcial que solo descubre sus ojos al hablar.","en":"A deep violet robe embroidered in gold thread, a partial mask that reveals only her eyes when she speaks.","proposal":false},{"es":"Paleta: violeta profundo y oro; el neón del universo se apaga a su alrededor, como si ella impusiera su propio silencio visual.","en":"Palette: deep violet and gold; the universe's neon dims around her, as if she imposes her own visual silence.","proposal":false}]},{"es":"Temperamento y Personalidad","en":"Temperament & Personality","pairs":[{"es":"Calmada hasta lo inquietante; nunca alza la voz, ni siquiera cuando niega el paso a un aspirante.","en":"Calm to an unsettling degree; she never raises her voice, not even when she denies an aspirant passage.","proposal":false},{"es":"Juzga por la intención, no por la fuerza; a Kairo lo detiene más de una vez, no para humillarlo sino para probarlo.","en":"She judges intention, not strength; she stops Kairo more than once, not to humiliate him but to test him.","proposal":false}]},{"es":"Rol en la Historia","en":"Role in the Story","pairs":[{"es":"Es el examen final del pilar: solo ante ella se decide si un Girador merece tocar la Rueda con sus propias manos.","en":"She is the pillar's final trial: only before her is it decided whether a Spinner deserves to touch the Wheel with their own hands.","proposal":false},{"es":"Su presencia conecta las puertas VIP con la Rueda misma: sin su aprobación, ninguna puerta —ni la sexta— realmente cuenta.","en":"Her presence connects the VIP gates to the Wheel itself: without her approval, no gate — not even the sixth — truly counts.","proposal":true},{"es":"Vega no compite contra los Giradores; los mide contra la única persona que de verdad importa: quienes eran antes de empezar.","en":"Vega does not compete against the Spinners; she measures them against the only person who truly matters: who they were before they began.","proposal":false}]},{"es":"Frases Clave","en":"Key Lines","pairs":[{"es":"\"No juzgo tu fuerza. Juzgo por qué quieres girarla.\"","en":"\"I do not judge your strength. I judge why you want to turn it.\"","proposal":false},{"es":"\"La Rueda no premia a quien más golpea las puertas, sino a quien no deja de cruzarlas.\"","en":"\"The Wheel does not reward whoever strikes the gates hardest, but whoever never stops crossing them.\"","proposal":false}]},{"es":"Ficha de Diseño (para keyframes)","en":"Design-Sheet Notes (for keyframes)","pairs":[{"es":"Vistas: frente (de pie ante el santuario de la Rueda, palmas abiertas), perfil con la túnica ondeando en el viento del santuario, espalda frente a la Rueda giratoria, expresión (serenidad→juicio), acción (deteniendo a un aspirante con un solo gesto dorado). Shonen-cyberpunk, violeta profundo sobre negro, oro solo en su gesto de juicio.","en":"Views: front (standing before the Wheel's sanctuary, palms open), profile with her robe billowing in the sanctuary wind, back facing the spinning Wheel, expression (serenity→judgment), action (stopping an aspirant with a single golden gesture). Shonen-cyberpunk, deep violet over black, gold only in her gesture of judgment.","proposal":false}]}]},{"id":"08","name":"Nyx","pillar":"anime","priority":"T2","color":"#E24D9C","color2":"#0B0E17","alias_es":"El Guardián de la Puerta","alias_en":"The Gatekeeper","sections":[{"es":"Datos Básicos","en":"Basic Information","pairs":[{"es":"Nombre: Nyx. Edad aparente: 22. Pilar: Universo Anime XSINO. Rival de Kairo en \"La Rueda del Destino\".","en":"Name: Nyx. Apparent age: 22. Pillar: XSINO Anime Universe. Kairo's rival in \"The Wheel of Destiny.\"","proposal":false},{"es":"Rol: guardiana de las puertas VIP más altas; su trabajo es rechazar, no acompañar.","en":"Role: guardian of the highest VIP gates; her job is to reject, not to guide.","proposal":false},{"es":"Se rumora que Nyx cruzó las seis puertas ella misma hace tiempo y decidió quedarse a bloquear a los demás.","en":"It is rumored Nyx cleared all six gates herself long ago and chose to stay behind, blocking everyone else.","proposal":true}]},{"es":"Apariencia y Diseño Visual","en":"Appearance & Visual Design","pairs":[{"es":"Complexión felina y precisa, cada movimiento calculado para intimidar antes de atacar.","en":"A feline, precise build, every movement calculated to intimidate before she strikes.","proposal":false},{"es":"Armadura negra ajustada con filos magenta encendidos, garras retráctiles que chispean neón al chocar contra una puerta.","en":"Tight black armor lined with glowing magenta edges, retractable claws that spark neon when they strike a gate.","proposal":false},{"es":"Paleta: magenta neón sobre negro; el color se intensifica cuando se burla de un aspirante que está a punto de rendirse.","en":"Palette: neon magenta over black; the color intensifies whenever she mocks an aspirant on the verge of quitting.","proposal":false}]},{"es":"Temperamento y Personalidad","en":"Temperament & Personality","pairs":[{"es":"Filosa y burlona; encuentra el punto exacto donde duele una duda y lo señala en voz alta.","en":"Sharp and mocking; she finds the exact spot where doubt hurts and calls it out loud.","proposal":false},{"es":"No odia a quienes rechaza —los pone a prueba de la única forma que conoce: haciéndolos enfurecer lo suficiente para no rendirse.","en":"She does not hate the ones she rejects — she tests them the only way she knows: making them angry enough not to quit.","proposal":false},{"es":"Se mide a sí misma contra los aspirantes que rechaza; cada uno que logra pasar es, en secreto, una victoria que ella también celebra.","en":"She measures herself against the aspirants she rejects; each one who finally gets past her is, secretly, a victory she celebrates too.","proposal":false}]},{"es":"Rol en la Historia","en":"Role in the Story","pairs":[{"es":"Es el obstáculo que convierte la determinación de Kairo en algo ganado, no regalado; sin ella, ninguna puerta pesaría lo mismo.","en":"She is the obstacle that turns Kairo's determination into something earned, not given; without her, no gate would carry the same weight.","proposal":false},{"es":"Su enfrentamiento final con Kairo en la sexta puerta es el clímax antes de que él llegue ante Vega.","en":"Her final clash with Kairo at the sixth gate is the climax before he stands before Vega.","proposal":true}]},{"es":"Frases Clave","en":"Key Lines","pairs":[{"es":"\"¿Ya quieres rendirte? Qué rápido. Pensé que durarías más.\"","en":"\"Ready to quit already? That was fast. I thought you'd last longer.\"","proposal":false},{"es":"\"No te bloqueo por crueldad. Te bloqueo porque aún no lo has ganado.\"","en":"\"I don't block you out of cruelty. I block you because you haven't earned it yet.\"","proposal":false}]},{"es":"Ficha de Diseño (para keyframes)","en":"Design-Sheet Notes (for keyframes)","pairs":[{"es":"Vistas: frente (de pie sobre la puerta VIP, garras extendidas), perfil en pose de ataque con destello magenta, espalda alejándose tras vencer a un aspirante, expresión (burla→sorpresa al ser superada), acción (chocando garras contra el puño dorado de Kairo). Shonen-cyberpunk, magenta neón sobre negro, sin oro salvo el reflejo del golpe de Kairo.","en":"Views: front (standing atop the VIP gate, claws extended), profile in an attack pose with a magenta flash, back walking away after defeating an aspirant, expression (mockery→surprise at being bested), action (claws clashing against Kairo's gold-lit fist). Shonen-cyberpunk, neon magenta over black, no gold except the reflection of Kairo's strike.","proposal":false}]}]},{"id":"09","name":"La Suerte","pillar":"whatif","priority":"T0","color":"#E8B84B","color2":"#0B0E17","alias_es":"La Suerte","alias_en":"Luck","sections":[{"es":"Datos Básicos","en":"Basic Information","pairs":[{"es":"Nombre: La Suerte. Edad: intemporal, sin edad ni género fijo. Pilar: ¿Y Si...? — con apariciones transversales en los otros tres pilares.","en":"Name: Luck (La Suerte). Age: timeless, with no fixed age or gender. Pillar: What If...? — with cross-pillar appearances in the other three.","proposal":false},{"es":"Rol: la voz y el anclaje de marca de XSINO; protagonista de \"¿Y Si la Suerte Tuviera Voz?\".","en":"Role: XSINO's brand voice and anchor; protagonist of \"What If Luck Had a Voice?\"","proposal":false},{"es":"No tiene historia de origen; siempre estuvo ahí, en el segundo antes de cada decisión humana.","en":"It has no origin story; it was always there, in the second before every human decision.","proposal":true}]},{"es":"Apariencia y Diseño Visual","en":"Appearance & Visual Design","pairs":[{"es":"Silueta luminosa y andrógina hecha enteramente de luz dorada, sin rasgos fijos, un contorno que respira como una llama calmada.","en":"A luminous, androgynous silhouette made entirely of golden light, with no fixed features, an outline that breathes like a calm flame.","proposal":false},{"es":"No usa ropa ni objetos; su forma cambia de intensidad según la emoción de la escena que observa.","en":"It wears no clothing or objects; its form shifts in intensity according to the emotion of the scene it watches.","proposal":false},{"es":"Paleta: oro puro sobre negro absoluto; ningún otro color comparte el cuadro cuando La Suerte aparece.","en":"Palette: pure gold over absolute black; no other color shares the frame when Luck appears.","proposal":false}]},{"es":"Temperamento y Personalidad","en":"Temperament & Personality","pairs":[{"es":"Habla con calma y sin apuro, como quien ya conoce el final de la historia pero respeta que el espectador la descubra solo.","en":"It speaks calmly and without hurry, like someone who already knows the ending but respects the viewer's right to discover it alone.","proposal":false},{"es":"Nunca promete un resultado; solo señala la puerta y deja que la decisión sea enteramente humana.","en":"It never promises an outcome; it only points to the door and leaves the decision entirely human.","proposal":false},{"es":"Tiene un humor seco y cercano, casi cómplice, que rompe la solemnidad justo antes de la pregunta final.","en":"It has a dry, warm humor, almost conspiratorial, that breaks the solemnity right before the final question.","proposal":false}]},{"es":"Rol en la Historia","en":"Role in the Story","pairs":[{"es":"Es el hilo conductor de toda la marca XSINO: puede aparecer como voz en off en \"La Moneda del Destino\", como silueta en \"El Abuelo y su Nieta\", o como Fortuna en el universo anime.","en":"It is the throughline of the entire XSINO brand: it can appear as a voiceover in \"The Coin of Destiny,\" as a silhouette in \"The Grandfather and His Granddaughter,\" or as Fortuna in the anime universe.","proposal":false},{"es":"Su formato nativo, \"¿Y Si...?\", es el más repetible de la marca: habla directo a cámara y termina siempre en una pregunta al espectador.","en":"Its native format, \"What If...?\", is the brand's most repeatable one: it speaks straight to camera and always ends on a question to the viewer.","proposal":false},{"es":"Encarna la tesis central sin rodeos: la suerte no es un premio que cae, es la decisión que la persona toma después de escucharla.","en":"It embodies the core thesis without detour: luck is not a prize that falls, it is the decision the person makes after listening to it.","proposal":false}]},{"es":"Frases Clave","en":"Key Lines","pairs":[{"es":"\"No vengo a decirte que vas a ganar. Vengo a preguntarte qué vas a decidir.\"","en":"\"I'm not here to tell you that you'll win. I'm here to ask what you'll decide.\"","proposal":false},{"es":"\"¿Y si la suerte, todo este tiempo, hubiera estado esperando tu respuesta?\"","en":"\"What if luck, this whole time, had been waiting for your answer?\"","proposal":false}]},{"es":"Ficha de Diseño (para keyframes)","en":"Design-Sheet Notes (for keyframes)","pairs":[{"es":"Vistas: frente (silueta completa iluminando la oscuridad, hablando a cámara), perfil disolviéndose en partículas doradas, espalda como un resplandor que se aleja, expresión (el \"rostro\" se insinúa solo con la intensidad de la luz), acción (extendiendo una mano de luz hacia el espectador). Gráfico minimalista, alto contraste, un solo foco dorado, sin fondo ni objetos.","en":"Views: front (full silhouette lighting the darkness, speaking to camera), profile dissolving into golden particles, back as a glow receding into distance, expression (the \"face\" is only suggested by the light's intensity), action (extending a hand of light toward the viewer). Minimal graphic style, high contrast, a single gold spotlight, no background or props.","proposal":false}]}]},{"id":"10","name":"Fortuna","pillar":"anime","priority":"T3","color":"#E8B84B","color2":"#B0E0E6","alias_es":"Fortuna","alias_en":"Fortune","sections":[{"es":"Datos Básicos","en":"Basic Information","pairs":[{"es":"Nombre: Fortuna. Edad aparente: intemporal. Pilar: Universo Anime XSINO. Encarnación anime de La Suerte dentro de \"La Rueda del Destino\".","en":"Name: Fortuna. Apparent age: timeless. Pillar: XSINO Anime Universe. Anime incarnation of Luck inside \"The Wheel of Destiny.\"","proposal":false},{"es":"Rol: espíritu viviente de la Rueda; la misma esencia de La Suerte, pero con cuerpo, voz y presencia dentro del universo de Kairo.","en":"Role: the living spirit of the Wheel; the same essence as Luck, but with a body, a voice, and a presence inside Kairo's universe.","proposal":false},{"es":"Aparece solo a quienes cruzan las seis puertas y llegan ante Vega; es la última cara de la suerte antes de girar la Rueda.","en":"She appears only to those who clear all six gates and stand before Vega; she is the last face of luck before the Wheel turns.","proposal":true}]},{"es":"Apariencia y Diseño Visual","en":"Appearance & Visual Design","pairs":[{"es":"Complexión etérea y flotante, como si no tocara del todo el suelo del santuario donde vive la Rueda.","en":"An ethereal, floating build, as if she never quite touches the sanctuary floor where the Wheel lives.","proposal":false},{"es":"Vestido de listones dorados e iridiscentes que cambian de color según el ángulo, cabello que se mueve como si estuviera bajo el agua.","en":"A gown of gold and iridescent ribbons that shift color with the angle, hair that moves as if underwater.","proposal":false},{"es":"Paleta: oro e iridiscencia sobre el neón shonen-cyberpunk; es la única figura del universo anime que refleja todos los colores del elenco a la vez.","en":"Palette: gold and iridescence over the shonen-cyberpunk neon; she is the only figure in the anime universe who reflects every cast color at once.","proposal":false}]},{"es":"Temperamento y Personalidad","en":"Temperament & Personality","pairs":[{"es":"Serena y juguetona a la vez, con un asombro genuino por cada aspirante que logra llegar hasta ella.","en":"Serene and playful at once, with genuine wonder for every aspirant who manages to reach her.","proposal":false},{"es":"No juzga como Vega ni bloquea como Nyx; su única función es hacer la pregunta que decide si la Rueda gira a favor de alguien.","en":"She doesn't judge like Vega or block like Nyx; her only function is to ask the question that decides whether the Wheel turns in someone's favor.","proposal":false}]},{"es":"Rol en la Historia","en":"Role in the Story","pairs":[{"es":"Es el puente narrativo entre \"¿Y Si...?\" y el universo anime: la misma Suerte, ahora con rostro, para quienes ya se ganaron verla.","en":"She is the narrative bridge between \"What If...?\" and the anime universe: the same Luck, now with a face, for those who have already earned the right to see her.","proposal":false},{"es":"Su aparición ante Kairo, tras superar a Nyx y ser aprobado por Vega, es el clímax visual de \"La Rueda del Destino\".","en":"Her appearance before Kairo, after he overcomes Nyx and is approved by Vega, is the visual climax of \"The Wheel of Destiny.\"","proposal":true},{"es":"Encarna, dentro del mito shonen, la misma tesis que La Suerte dice en el pilar ¿Y Si...?: la Rueda no regala nada que la persona no haya decidido merecer.","en":"Within the shonen myth, she embodies the same thesis Luck speaks in the What If...? pillar: the Wheel gives nothing the person hasn't already decided to earn.","proposal":false}]},{"es":"Frases Clave","en":"Key Lines","pairs":[{"es":"\"Llegaste hasta aquí no por suerte, sino a pesar de ella.\"","en":"\"You made it here not because of luck, but in spite of it.\"","proposal":false},{"es":"\"La Rueda ya te vio decidir. Ahora solo falta que gire.\"","en":"\"The Wheel already saw you decide. Now all that's left is for it to turn.\"","proposal":false}]},{"es":"Ficha de Diseño (para keyframes)","en":"Design-Sheet Notes (for keyframes)","pairs":[{"es":"Vistas: frente (flotando ante la Rueda detenida, listones dorados en movimiento), perfil con la Rueda encendiéndose detrás, espalda disolviéndose en partículas iridiscentes, expresión (asombro→calidez), acción (tocando la Rueda para que comience a girar). Shonen-cyberpunk, oro e iridiscencia sobre negro, el único personaje que ilumina toda la escena a su alrededor.","en":"Views: front (floating before the stilled Wheel, gold ribbons in motion), profile with the Wheel igniting behind her, back dissolving into iridescent particles, expression (wonder→warmth), action (touching the Wheel so it begins to turn). Shonen-cyberpunk, gold and iridescence over black, the only character who lights the whole scene around her.","proposal":false}]}]}],"stories":[{"id":"01","title_es":"La Moneda del Destino","title_en":"The Coin of Destiny","pillar":"inspire","brand":"xsino","logline":{"es":"Un mecánico de 25 años cierra otra jornada agotadora sin que el dinero le alcance; una moneda dorada y misteriosa detiene el tiempo por un instante y le regala, no riqueza, sino la claridad para decidir qué sigue.","en":"A 25-year-old mechanic closes another exhausting shift without enough money to cover what he needs; a mysterious golden coin freezes time for an instant and gives him, not riches, but the clarity to choose what comes next."},"thesis":{"es":"La suerte no cambia el pasado. Cambia lo que decides hacer con el momento siguiente.","en":"Luck doesn't change the past. It changes what you decide to do with the next moment."},"shots":[{"n":1,"slug":"INT. TALLER MECÁNICO — MADRUGADA · Plano general, time-lapse suave; se abre la cortina metálica, las luces se encienden una a una.","action_es":"Mateo abre el taller al amanecer. Su ropa ya lleva las manchas de grasa de mil mañanas iguales.","action_en":"Mateo opens the shop at dawn. His clothes already carry the grease stains of a thousand identical mornings.","vo_es":"Cada mañana empieza igual. Y así se repiten los días.","vo_en":"Every morning starts the same. And that's how the days repeat."},{"n":2,"slug":"INT. TALLER MECÁNICO — DÍA · Montaje en cámara rápida; herramientas, motores, sudor en la frente.","action_es":"Repara un motor, luego otro. Se limpia el sudor con el brazo. El taller suena a metal y a esfuerzo, sin una sola palabra.","action_en":"He repairs one engine, then another. He wipes sweat with his forearm. The shop sounds like metal and effort, without a single word.","vo_es":"Sin quejarse. Sin detenerse. Así ha sido siempre.","vo_en":"No complaints. No stopping. That's how it's always been."},{"n":3,"slug":"EXT. CALLE DEL BARRIO — ATARDECER · Plano medio; camina solo hacia casa, hombros caídos.","action_es":"El sol cae mientras camina a casa. Cansado, pero con la cabeza en alto por costumbre, no por ánimo.","action_en":"The sun sets as he walks home. Tired, but with his head up out of habit, not spirit.","vo_es":"Otro turno terminado. Otra noche por delante.","vo_en":"Another shift done. Another night ahead."},{"n":4,"slug":"INT. COCINA DE MATEO — NOCHE · Plano medio fijo; se sienta solo en la mesa pequeña, luz cálida y suave.","action_es":"Vacía su billetera sobre la mesa y cuenta lo ganado en el día, billete por billete.","action_en":"He empties his wallet onto the table and counts the day's earnings, bill by bill.","vo_es":"Contó cada billete, como quien cuenta lo que aún le falta.","vo_en":"He counted every bill, like someone counting what's still missing."},{"n":5,"slug":"PRIMER PLANO — Mateo suspira; el dinero no alcanza. Baja la mirada, desanimado pero no vencido.","action_es":"No alcanza para todo lo que necesita. Suspira, resignado, pero no se derrumba.","action_en":"It's not enough to cover everything he needs. He sighs, resigned, but he doesn't break.","vo_es":"No alcanzaba. Otra vez. Pero seguía de pie.","vo_en":"It wasn't enough. Again. But he was still standing."},{"n":6,"slug":"INSERTO — Una moneda dorada y misteriosa rueda lentamente por el piso de la cocina.","action_es":"De la nada, una moneda dorada rueda por el suelo, girando despacio hacia él.","action_en":"Out of nowhere, a golden coin rolls across the floor, spinning slowly toward him.","vo_es":"Y entonces, algo rodó hasta sus pies.","vo_en":"And then, something rolled to his feet."},{"n":7,"slug":"EL MOMENTO — Congelación total de tiempo; el reloj se detiene, el polvo queda suspendido en el aire, silencio absoluto.","action_es":"Todo se congela. El reloj se detiene. El polvo queda flotando en el aire. Un silencio total llena el cuarto.","action_en":"Everything freezes. The clock stops. Dust hangs suspended in the air. Total silence fills the room.","vo_es":"El tiempo se detuvo, como si esperara su respuesta.","vo_en":"Time stopped, as if waiting for his answer."},{"n":8,"slug":"PRIMER PLANO — Mateo se agacha despacio y recoge la moneda dorada, que brilla con luz propia.","action_es":"Se agacha despacio y toma la moneda entre los dedos. Brilla como si tuviera luz propia.","action_en":"He kneels slowly and takes the coin between his fingers. It glows as if lit from within.","vo_es":"No puedes cambiar el pasado... Pero siempre puedes elegir lo que sigue.","vo_en":"You can't change the past... But you can always choose what comes next."},{"n":9,"slug":"PRIMER PLANO — La moneda resbala de su mano; cae en cámara lenta y el tiempo vuelve a moverse.","action_es":"La moneda se le resbala de la mano. Cae en cámara lenta, y el tiempo empieza a moverse de nuevo.","action_en":"The coin slips from his hand. It falls in slow motion, and time begins to move again.","vo_es":"La moneda cayó. El instante, no.","vo_en":"The coin fell. The instant didn't."},{"n":10,"slug":"PLANO MEDIO — En vez de volverse rico, su expresión cambia; sonríe con renovada confianza y se pone de pie.","action_es":"No se hizo rico. Pero algo en su rostro cambió: sonríe con una confianza que no tenía hace un minuto. Se levanta.","action_en":"He didn't become rich. But something in his face changed: he smiles with a confidence he didn't have a minute ago. He stands up.","vo_es":"No cambió su bolsillo. Cambió su mirada.","vo_en":"It didn't change his pocket. It changed his outlook."},{"n":11,"slug":"PRIMER PLANO — Toma su teléfono y abre la aplicación XSINO; sus ojos reflejan optimismo.","action_es":"Toma su teléfono y abre la app de XSINO. Sus ojos, por primera vez esa noche, reflejan esperanza.","action_en":"He picks up his phone and opens the XSINO app. His eyes, for the first time all night, reflect hope.","vo_es":"Eligió la esperanza. Eligió intentarlo.","vo_en":"He chose hope. He chose to try."},{"n":12,"slug":"CIERRE — Negro. Aparece el logo dorado de XSINO con iluminación elegante.","action_es":"XSINO — La suerte favorece a quienes nunca dejan de intentarlo.","action_en":"XSINO — Luck favors those who never stop trying.","vo_es":"La suerte favorece a quien nunca deja de intentarlo.","vo_en":"Luck favors those who never stop trying."}]},{"id":"02","title_es":"El Abuelo y su Nieta","title_en":"The Grandfather and His Granddaughter","pillar":"inspire","brand":"xsino","logline":{"es":"Una niña de 7 años le pregunta a su abuelo si alguna vez se ganó la lotería; la respuesta de él no está en las palabras, sino en toda una vida compartida con ella.","en":"A 7-year-old girl asks her grandfather if he ever won the lottery; his answer isn't in words, but in a whole life shared with her."},"thesis":{"es":"La suerte no siempre llega en un boleto. A veces llega con el nombre de alguien que amas.","en":"Luck doesn't always arrive on a ticket. Sometimes it arrives with the name of someone you love."},"shots":[{"n":1,"slug":"EXT. JARDÍN — TARDE · Plano medio; la niña y el abuelo sentados en una banca de madera, luz cálida de tarde.","action_es":"Sofía, de 7 años, mira a su abuelo con curiosidad genuina. \"Abuelo... ¿alguna vez te ganaste la lotería?\"","action_en":"Sofía, 7 years old, looks at her grandfather with genuine curiosity. \"Grandpa... did you ever win the lottery?\"","vo_es":"Hay preguntas que los niños hacen sin saber lo grandes que son.","vo_en":"Some questions children ask without knowing how big they are."},{"n":2,"slug":"EXT. JARDÍN — TARDE · Primer plano; el abuelo sonríe con calidez antes de responder.","action_es":"El abuelo sonríe con ternura. \"No.\" Ella ladea la cabeza. \"Entonces... creo que nunca tuviste suerte.\" Él solo sonríe, sin responder.","action_en":"The grandfather smiles warmly. \"No.\" She tilts her head. \"Then... I guess you were never lucky.\" He simply smiles, without answering.","vo_es":"Él no dijo nada. Prefirió mostrárselo.","vo_en":"He said nothing. He chose to show her instead."},{"n":3,"slug":"EXT. JARDÍN — TARDE · Plano general; el abuelo se levanta y le toma la mano; empieza un montaje cálido.","action_es":"Se pone de pie y la toma de la mano. Sin decir una palabra más, empieza a mostrarle lo que la lotería nunca le dio.","action_en":"He stands and takes her hand. Without another word, he begins showing her what the lottery never gave him.","vo_es":"Empezó a enseñarle sin usar ni una palabra más.","vo_en":"He began teaching her without using another word."},{"n":4,"slug":"MONTAJE — EXT. CALLE DEL BARRIO — TARDE · Planos cortos encadenados, luz dorada de hora mágica.","action_es":"Le enseña a andar en bicicleta con paciencia. La atrapa justo antes de caer; ambos ríen.","action_en":"He patiently teaches her to ride a bike. He catches her just before she falls; they both laugh.","vo_es":"Cada caída tenía sus manos esperando abajo.","vo_en":"Every fall had his hands waiting underneath."},{"n":5,"slug":"MONTAJE — EXT. JARDÍN / INT. COCINA — TARDE · Continuación del montaje; riegan flores, preparan chocolate caliente.","action_es":"Riegan juntos las flores de colores. Después, en la cocina, preparan chocolate caliente entre risas.","action_en":"They water the colorful flowers together. Later, in the kitchen, they make hot chocolate between laughs.","vo_es":"Ninguna de esas tardes costaba nada. Y todas valían todo.","vo_en":"None of those afternoons cost anything. And all of them were worth everything."},{"n":6,"slug":"MONTAJE — INT. COCINA — TARDE · Continuación; hornean galletas y hacen un desastre divertido.","action_es":"Hornean galletas y terminan cubiertos de harina, riendo del desastre que hicieron juntos.","action_en":"They bake cookies and end up covered in flour, laughing at the mess they made together.","vo_es":"El desorden también sabía a suerte.","vo_en":"Even the mess tasted like luck."},{"n":7,"slug":"EXT. PORCHE — ATARDECER · Plano medio; se sientan juntos a ver la puesta de sol, luego un álbum de fotos viejo.","action_es":"Se sientan en el porche a ver el atardecer. Él abre un álbum viejo lleno de recuerdos familiares.","action_en":"They sit on the porch watching the sunset. He opens an old album full of family memories.","vo_es":"Las fotos viejas guardan lo que el dinero no puede comprar.","vo_en":"Old photos hold what money can't buy."},{"n":8,"slug":"PRIMER PLANO — Sofía mira las fotos con una sonrisa y luego lo abraza fuerte.","action_es":"Ella sonríe mirando las fotos y lo abraza con fuerza, sin saber todavía lo que está a punto de escuchar.","action_en":"She smiles looking at the photos and hugs him tight, not yet knowing what she's about to hear.","vo_es":"Lo abrazó sin saber que ya tenía la respuesta en los brazos.","vo_en":"She hugged him without knowing she already had the answer in her arms."},{"n":9,"slug":"EL MOMENTO — EXT. PORCHE — ATARDECER · El sol cae; el abuelo la mira con amor.","action_es":"Mientras el sol se pone, el abuelo la mira con amor y dice suavemente: \"La suerte nunca fue sobre el dinero...\"","action_en":"As the sun sets, the grandfather looks at her with love and softly says: \"Luck was never about money...\"","vo_es":"La suerte nunca fue sobre el dinero...","vo_en":"Luck was never about money..."},{"n":10,"slug":"PRIMER PLANO — Le toca la mejilla con ternura.","action_es":"Le toca la mejilla con ternura. \"Mi mayor suerte... siempre has sido tú.\" Ella sonríe y lo abraza.","action_en":"He gently touches her cheek. \"My greatest luck... has always been you.\" She smiles and hugs him.","vo_es":"Mi mayor suerte... siempre has sido tú.","vo_en":"My greatest luck... has always been you."},{"n":11,"slug":"CIERRE — Negro. Texto dorado elegante aparece lentamente.","action_es":"\"La vida está llena de momentos inesperados.\" Una pausa. Luego, el logo de XSINO aparece con una luz dorada sutil.","action_en":"\"Life is full of unexpected moments.\" A pause. Then, the XSINO logo fades in with a subtle golden light.","vo_es":"Celebra cada momento. Disfruta cada oportunidad.","vo_en":"Celebrate every moment. Enjoy every opportunity."}]},{"id":"03","title_es":"Cada Día una Oportunidad","title_en":"Every Day a New Opportunity","pillar":"inspire","brand":"xsino","logline":{"es":"Un joven de mediados de sus veinte enfrenta un rechazo tras otro —una cancha, una oficina, una entrevista— y sigue caminando, convencido de que un día todo puede cambiar.","en":"A young man in his mid-20s faces one rejection after another — a field, an office, an interview — and keeps walking, convinced that one day everything can change."},"thesis":{"es":"La resiliencia no es no caerse. Es seguir caminando después de cada rechazo.","en":"Resilience isn't never falling. It's still walking after every rejection."},"shots":[{"n":1,"slug":"EXT. CANCHA DE FÚTBOL — TARDE · Plano general; partido amateur entre amigos, jugada decisiva.","action_es":"Diego, mediados de sus veinte, falla el tiro decisivo en el último minuto del partido.","action_en":"Diego, in his mid-20s, misses the decisive shot in the match's final minute.","vo_es":"Un tiro. Un segundo. Y todo se decide, o no.","vo_en":"One shot. One second. And everything is decided, or not."},{"n":2,"slug":"PRIMER PLANO — Sus compañeros bajan la cabeza, decepcionados; Diego respira, sonríe y se retira.","action_es":"Sus compañeros bajan la cabeza. Diego agacha la mirada un instante, luego sonríe, se encoge de hombros y palmea el hombro de un compañero. Se va del campo con calma.","action_en":"His teammates lower their heads. Diego lowers his gaze for a moment, then smiles, shrugs, and pats a teammate's shoulder. He walks off the field with quiet confidence.","vo_es":"No ganó. Pero tampoco se fue derrotado.","vo_en":"He didn't win. But he didn't leave defeated either."},{"n":3,"slug":"INT. OFICINA MODERNA — DÍA · Plano medio; Diego presenta una propuesta a un cliente potencial.","action_es":"Diego presenta su idea con convicción. El cliente niega con la cabeza, cortés. La propuesta queda rechazada.","action_en":"Diego presents his idea with conviction. The client politely shakes his head. The proposal is rejected.","vo_es":"Otra puerta que no se abrió. Todavía.","vo_en":"Another door that didn't open. Yet."},{"n":4,"slug":"PLANO MEDIO — Diego agradece con sinceridad, toma su libreta y se retira con dignidad.","action_es":"Les agradece el tiempo, sonríe con sinceridad, recoge su libreta y sale de la oficina con la frente en alto.","action_en":"He thanks them for their time, smiles sincerely, picks up his notebook, and leaves the office with his head held high.","vo_es":"Salió con las manos vacías y la dignidad intacta.","vo_en":"He walked out empty-handed, dignity intact."},{"n":5,"slug":"EXT. AFUERA DE LA ENTREVISTA — DÍA · Plano medio; sentado afuera después de una entrevista de trabajo, su teléfono vibra.","action_es":"El teléfono vibra. El mensaje dice: \"Gracias por aplicar. Decidimos avanzar con otro candidato.\"","action_en":"His phone vibrates. The message reads: \"Thank you for applying. We've decided to move forward with another candidate.\"","vo_es":"Gracias por aplicar. Decidimos avanzar con otro candidato.","vo_en":"Thank you for applying. We've decided to move forward with another candidate."},{"n":6,"slug":"PRIMER PLANO — Diego respira profundo, sonríe con suavidad, guarda el teléfono y sigue caminando.","action_es":"Respira hondo. Sonríe apenas. Guarda el teléfono en el bolsillo y sigue caminando, sin detenerse.","action_en":"He takes a deep breath. He smiles gently. He puts the phone away and keeps walking, without stopping.","vo_es":"Un no más. Un paso más.","vo_en":"One more no. One more step."},{"n":7,"slug":"EXT. CALLE — DÍA · Plano general; una lluvia repentina y fuerte comienza a caer.","action_es":"Camina a casa cuando empieza a llover fuerte. Todos corren a resguardarse. Él simplemente se ríe.","action_en":"He's walking home when heavy rain suddenly begins. Everyone runs for cover. He simply laughs.","vo_es":"Todos corrieron. Él se quedó a disfrutarla.","vo_en":"Everyone ran. He stayed to enjoy it."},{"n":8,"slug":"PLANO MEDIO — Sigue caminando bajo la lluvia, mirando hacia el cielo; la música se vuelve más optimista.","action_es":"Sigue caminando entre la lluvia, con la mirada hacia arriba, como si el cielo también le estuviera dando la razón.","action_en":"He keeps walking through the rain, looking up at the sky, as if the sky were proving him right too.","vo_es":"A veces hay que mojarse para sentir que sigues vivo.","vo_en":"Sometimes you have to get soaked to feel like you're still alive."},{"n":9,"slug":"EXT. BANCA DE PARQUE — ATARDECER · Plano medio; un amigo se sienta junto a él.","action_es":"Al atardecer, un amigo se sienta a su lado y le pregunta: \"¿Cómo es que nunca te rindes?\"","action_en":"At sunset, a friend sits beside him and asks: \"How come you never give up?\"","vo_es":"¿Cómo es que nunca te rindes?","vo_en":"How come you never give up?"},{"n":10,"slug":"PRIMER PLANO — Diego mira el horizonte, sonríe en paz, y responde con calma.","action_es":"Mira hacia el horizonte. Sonríe, en paz. \"Porque un día...\" — una pausa — \"...todo puede cambiar.\"","action_en":"He looks toward the horizon. He smiles, at peace. \"Because one day...\" — a pause — \"...everything can change.\"","vo_es":"Porque un día... todo puede cambiar.","vo_en":"Because one day... everything can change."},{"n":11,"slug":"PLANO GENERAL — Silencio; la cámara se aleja lentamente de los dos en la banca.","action_es":"Silencio. La cámara retrocede despacio, dejándolo ahí, tranquilo, mirando hacia adelante.","action_en":"Silence. The camera slowly pulls back, leaving him there, calm, looking ahead.","vo_es":"Y en ese silencio, ya lo había dicho todo.","vo_en":"And in that silence, he'd already said it all."},{"n":12,"slug":"CIERRE — Negro. Texto dorado elegante: \"Cada día es una nueva oportunidad.\" Aparece el logo XSINO.","action_es":"\"Cada día es una nueva oportunidad.\" Una pausa. Luego, el logo de XSINO se funde con una iluminación cinematográfica dorada.","action_en":"\"Every day is a new opportunity.\" A pause. Then, the XSINO logo fades in with cinematic golden lighting.","vo_es":"Cree en nuevas posibilidades.","vo_en":"Believe in new possibilities."}]},{"id":"04","title_es":"Dos Extraños","title_en":"Two Strangers","pillar":"love","brand":"heaven","logline":{"es":"Camila y Tomás viven la misma rutina en dos ciudades distintas sin saberlo —las mismas tazas, la misma canción, la misma app— hasta que el destino los cruza en un festival donde ninguno esperaba encontrar nada.","en":"Camila and Tomás live the same routine in two different cities without knowing it — the same mugs, the same song, the same app — until fate crosses their paths at a festival where neither expected to find anything."},"thesis":{"es":"Las mejores sorpresas de la vida no pasan en una pantalla. Pasan cuando los caminos se cruzan.","en":"Life's best surprises don't happen on a screen. They happen when paths cross."},"shots":[{"n":1,"slug":"INT. CAFETERÍA, CIUDAD A — DÍA · Pantalla dividida; plano medio de Camila en una cafetería acogedora.","action_es":"Camila, una joven de estilo elegante, se sienta en una cafetería tranquila. No tiene idea de que, en otra ciudad, alguien vive su misma mañana.","action_en":"Camila, a stylish young woman, sits in a quiet coffee shop. She has no idea that, in another city, someone is living her exact same morning.","vo_es":"Dos vidas, la misma mañana, sin saberlo todavía.","vo_en":"Two lives, the same morning, not knowing it yet."},{"n":2,"slug":"INT. CAFETERÍA, CIUDAD B — DÍA · Pantalla dividida continúa; plano medio de Tomás en otra cafetería.","action_es":"En otra ciudad, Tomás se sienta en su propia cafetería de siempre. Ninguno de los dos sabe que el otro existe.","action_en":"In another city, Tomás sits in his own usual coffee shop. Neither of them knows the other exists.","vo_es":"Ninguno sabía del otro. Todavía.","vo_en":"Neither knew about the other. Not yet."},{"n":3,"slug":"INSERTO — Ambos, en pantalla dividida, abren la app HeavenOnline en sus teléfonos durante su descanso.","action_es":"Los dos abren la app de HeavenOnline en el mismo instante, con la misma expresión relajada, sin saber que comparten el gesto.","action_en":"Both open the HeavenOnline app at the same instant, with the same relaxed expression, not knowing they share the gesture.","vo_es":"El mismo gesto, a cientos de calles de distancia.","vo_en":"The same gesture, hundreds of streets apart."},{"n":4,"slug":"MONTAJE — Pantalla dividida; ambos beben café de tazas de cerámica color mostaza idénticas.","action_es":"Camila bebe de una taza mostaza. Tomás bebe de una taza idéntica. Ninguno lo sabrá jamás, pero comparten hasta la taza.","action_en":"Camila drinks from a mustard-yellow mug. Tomás drinks from an identical one. Neither will ever know it, but they even share the mug.","vo_es":"La misma taza, en dos manos que nunca se han tocado.","vo_en":"The same mug, in two hands that have never touched."},{"n":5,"slug":"MONTAJE — Pantalla dividida; ambos se ponen una chaqueta azul marino, la misma canción indie suena en cada café.","action_es":"Ambos se ponen la misma chaqueta azul marino. En los dos cafés suena, sin que nadie lo note, la misma canción indie.","action_en":"Both put on the same navy-blue jacket. In both cafés, without anyone noticing, the same indie song plays.","vo_es":"La misma canción, sonando para dos que aún no se conocen.","vo_en":"The same song, playing for two who don't know each other yet."},{"n":6,"slug":"MONTAJE — Pantalla dividida; ambos sonríen casi al mismo tiempo mirando sus teléfonos, luego cierran la app y siguen su día.","action_es":"Ambos sonríen casi al mismo segundo, mirando la pantalla. Cierran la app y siguen con su día, cada uno mirando por la ventana como pensando en lo que vendrá.","action_en":"Both smile at almost the same second, looking at the screen. They close the app and continue their day, each gazing out the window as if thinking about what's coming.","vo_es":"Dos miradas, la misma pregunta sin hacer.","vo_en":"Two gazes, the same question unasked."},{"n":7,"slug":"EXT. FESTIVAL / RECINTO — NOCHE · Plano general; días después, un festival lleno de luces de colores y música en vivo.","action_es":"Días después, un festival estalla en luces y música. Camila llega con sus amigas. Tomás llega, por otro lado, con los suyos.","action_en":"Days later, a festival bursts with lights and music. Camila arrives with her friends. Tomás arrives, from another direction, with his.","vo_es":"Los dos llegaron al mismo lugar. Por caminos distintos.","vo_en":"They both arrived at the same place. By different paths."},{"n":8,"slug":"PLANO GENERAL — Ambos caminan entre la multitud sin notarse; varios casi-encuentros aumentan la tensión.","action_es":"Se cruzan entre la gente varias veces sin darse cuenta. Un giro, una distracción, y el momento se escapa una y otra vez.","action_en":"They cross paths among the crowd several times without noticing. A turn, a distraction, and the moment slips away again and again.","vo_es":"Tan cerca, tantas veces, sin saberlo.","vo_en":"So close, so many times, without knowing it."},{"n":9,"slug":"EL MOMENTO — Congelación de tiempo. Ambos extienden la mano hacia el mismo token conmemorativo del festival.","action_es":"El tiempo se detiene. Las manos de Camila y Tomás quedan suspendidas en el aire, a punto de tocar el mismo token del festival.","action_en":"Time stops. Camila's and Tomás's hands hang suspended in the air, about to touch the same festival token.","vo_es":"Un objeto. Dos manos. Un cruce que ya estaba escrito.","vo_en":"One object. Two hands. A crossing that was already written."},{"n":10,"slug":"PRIMER PLANO — Sus manos se tocan sobre el token; se miran, sorprendidos, en silencio.","action_es":"Sus manos se rozan sobre el mismo token. Se miran. Un instante de silencio antes de sonreír, genuinos, sin drama.","action_en":"Their hands touch over the same token. They look at each other. A moment of silence before they smile, genuine, without drama.","vo_es":"No fue un rayo. Fue solo... verdad.","vo_en":"It wasn't lightning. It was just... true."},{"n":11,"slug":"PLANO MEDIO — La música se eleva suavemente; ambos sonríen mientras el festival sigue a su alrededor.","action_es":"La música crece con suavidad alrededor de ellos. Sonríen, todavía con la mano cerca de la del otro, mientras el festival sigue su curso.","action_en":"The music swells softly around them. They smile, hands still close to each other's, as the festival carries on around them.","vo_es":"Todo lo demás siguió moviéndose. Ellos, por un instante, no.","vo_en":"Everything else kept moving. For a moment, they didn't."},{"n":12,"slug":"CIERRE — Negro. Texto dorado elegante aparece.","action_es":"\"Algunas de las mejores sorpresas de la vida no pasan en una pantalla...\" Pausa. \"...pasan cuando los caminos se cruzan.\" El logo de HeavenOnline aparece con luz dorada.","action_en":"\"Some of life's best surprises don't happen on a screen...\" Pause. \"...they happen when paths cross.\" The HeavenOnline logo fades in with golden light.","vo_es":"Cada momento puede traer algo inesperado.","vo_en":"Every moment can bring something unexpected."}]},{"id":"05","title_es":"El Sueño","title_en":"The Dream","pillar":"inspire","brand":"heaven","logline":{"es":"Un niño de 8 años juega fútbol con un balón gastado en una calle polvorienta mientras otros se burlan de su sueño; años de entrenamiento silencioso lo llevan, por fin, al túnel de un estadio —sin que nadie vea todavía su rostro.","en":"An 8-year-old boy plays soccer with a worn-out ball on a dusty street while others mock his dream; years of quiet training finally lead him to a stadium tunnel — his face still unseen by anyone."},"thesis":{"es":"Toda gran historia empieza con un sueño que nadie más puede ver todavía.","en":"Every great story begins with a dream no one else can see yet."},"shots":[{"n":1,"slug":"EXT. CALLE POLVORIENTA — ATARDECER · Plano general; el niño driblea un balón viejo entre porterías improvisadas de madera.","action_es":"En un barrio humilde, un niño de 8 años juega con un balón gastado entre postes de madera. Sus zapatos están viejos, su ropa es sencilla, su sonrisa no.","action_en":"In a humble neighborhood, an 8-year-old boy plays with a worn-out ball between wooden posts. His shoes are old, his clothes are simple, his smile isn't.","vo_es":"Todo empezó en una calle que nadie recordaría.","vo_en":"It all began on a street no one would remember."},{"n":2,"slug":"PLANO MEDIO — Otros niños se ríen cerca; uno le grita desde lejos.","action_es":"Unos niños cercanos se ríen. Uno le grita: \"Nunca vas a ser un futbolista de verdad.\" El niño no responde. Solo sonríe y sigue jugando.","action_en":"Some nearby kids laugh. One shouts at him: \"You'll never be a real football player.\" The boy doesn't respond. He just smiles and keeps playing.","vo_es":"Nunca vas a ser un futbolista de verdad.","vo_en":"You'll never be a real football player."},{"n":3,"slug":"MONTAJE — EXT. CALLE — ANTES DEL AMANECER · Planos cortos; el niño entrena solo, antes de que salga el sol.","action_es":"Entrena solo, antes del amanecer, cuando nadie más está mirando.","action_en":"He trains alone, before sunrise, when no one else is watching.","vo_es":"Nadie lo veía entrenar. Por eso, nadie lo vio dudar tampoco.","vo_en":"No one saw him train. That's why no one saw him doubt, either."},{"n":4,"slug":"MONTAJE — EXT. CAMPO BAJO LLUVIA / COLINA — DÍA · Continuación; entrena bajo la lluvia, corre cuesta arriba con el balón.","action_es":"Entrena bajo la lluvia cuando todos los demás se han ido a casa. Corre cuesta arriba cargando el balón.","action_en":"He trains in the rain when everyone else has gone home. He runs up steep hills carrying the ball.","vo_es":"Subía la colina una y otra vez. No por castigo. Por costumbre.","vo_en":"He climbed the hill again and again. Not as punishment. As habit."},{"n":5,"slug":"MONTAJE — Practica tiros libres una y otra vez; cae, se levanta, sigue.","action_es":"Repite el mismo tiro libre, una y otra vez. Se cae. Se levanta. Sigue.","action_en":"He repeats the same free kick, over and over. He falls. He gets up. He keeps going.","vo_es":"Cada caída tenía la misma respuesta: levantarse.","vo_en":"Every fall had the same answer: get back up."},{"n":6,"slug":"MONTAJE — Las estaciones cambian; el niño crece y se convierte en adolescente.","action_es":"Las estaciones cambian a su alrededor. El niño se convierte, poco a poco, en un adolescente.","action_en":"The seasons change around him. Little by little, the boy becomes a teenager.","vo_es":"El tiempo pasaba. El sueño, no.","vo_en":"Time passed. The dream didn't."},{"n":7,"slug":"MONTAJE — Los campos vacíos se transforman en canchas de entrenamiento profesional; ahora es un joven adulto, humilde pero firme.","action_es":"Los campos vacíos se convierten en canchas profesionales. Ahora es un joven adulto: su confianza ha crecido, pero su humildad, también.","action_en":"The empty fields become professional training grounds. He's a young adult now: his confidence has grown, but so has his humility.","vo_es":"Creció su confianza. Nunca creció su orgullo.","vo_en":"His confidence grew. His pride never did."},{"n":8,"slug":"INT. TÚNEL DE JUGADORES — NOCHE · Plano trasero; camina lento por el túnel de un estadio masivo, cámara detrás de él, sin revelar su rostro.","action_es":"De noche, en un estadio inmenso, camina despacio por el túnel de jugadores. La cámara lo sigue desde atrás. Su rostro nunca se revela.","action_en":"At night, in a massive stadium, he walks slowly through the players' tunnel. The camera follows from behind. His face is never revealed.","vo_es":"Miles lo esperaban del otro lado. Ninguno sabía todavía su nombre.","vo_en":"Thousands waited on the other side. None of them knew his name yet."},{"n":9,"slug":"PLANO GENERAL — Llega a la boca del túnel; las luces del estadio brillan al frente, miles de aficionados rugen a la distancia.","action_es":"Llega a la boca del túnel. Las luces del estadio arden frente a él. Miles de aficionados rugen a lo lejos. El ambiente es eléctrico.","action_en":"He reaches the mouth of the tunnel. The stadium lights blaze ahead of him. Thousands of fans roar in the distance. The atmosphere is electric.","vo_es":"El anunciador del estadio dice: \"Bienvenido...\"","vo_en":"The stadium announcer says: \"Welcome...\""},{"n":10,"slug":"PRIMER PLANO — El público estalla; él toma un último respiro profundo antes de salir.","action_es":"El público estalla en gritos. Él toma un último respiro profundo.","action_en":"The crowd erupts. He takes one final deep breath.","vo_es":"El público estalló.","vo_en":"The crowd erupts."},{"n":11,"slug":"PLANO GENERAL — Da un paso hacia el campo; corte antes de revelar su identidad.","action_es":"Da un paso hacia el campo. Corte antes de que se revele su identidad.","action_en":"He steps onto the field. Cut before his identity is revealed.","vo_es":"Todavía no sabíamos su nombre. Pero ya conocíamos su historia.","vo_en":"We still didn't know his name. But we already knew his story."},{"n":12,"slug":"CIERRE — Negro. Texto elegante blanco y dorado aparece lentamente.","action_es":"\"Toda gran historia empieza con un sueño.\" Pausa. \"Nunca dejes de creer.\" El logo de HeavenOnline aparece con luz dorada sutil.","action_en":"\"Every great story begins with a dream.\" Pause. \"Never stop believing.\" The HeavenOnline logo fades in with subtle golden light.","vo_es":"Sueña en grande. Disfruta el camino.","vo_en":"Dream big. Enjoy the journey."}]},{"id":"06","title_es":"El Viaje","title_en":"The Journey","pillar":"inspire","brand":"heaven","logline":{"es":"Un viajero solitario de unos 30 años cruza montañas, desiertos y tormentas en busca de la cima de una montaña; al llegar, no encuentra ningún tesoro —solo la paz de haber llegado.","en":"A lone traveler in his 30s crosses mountains, deserts, and storms in search of a mountain's summit; when he arrives, he finds no treasure — only the peace of having arrived."},"thesis":{"es":"La recompensa más grande nunca fue el destino. Fue el camino.","en":"The greatest reward was never the destination. It was the journey."},"shots":[{"n":1,"slug":"EXT. BORDE DE UN VALLE — ANTES DEL AMANECER · Plano general; un viajero solitario con mochila mira el horizonte antes de partir.","action_es":"Antes del amanecer, un viajero de unos 30 años se detiene al borde de un valle silencioso. Mira el horizonte una última vez.","action_en":"Before sunrise, a traveler in his 30s stops at the edge of a quiet valley. He takes one last look at the horizon.","vo_es":"Antes de cada viaje, hay un último momento de quietud.","vo_en":"Before every journey, there's one last moment of stillness."},{"n":2,"slug":"PLANO MEDIO — Sin dudarlo, empieza a caminar; solo se escucha el viento y aves distantes.","action_es":"Sin dudarlo, empieza a caminar. Solo el viento y unas aves lejanas rompen el silencio.","action_en":"Without hesitation, he starts walking. Only the wind and distant birds break the silence.","vo_es":"No dudó. Simplemente caminó.","vo_en":"He didn't hesitate. He just walked."},{"n":3,"slug":"MONTAJE — EXT. SENDEROS DE MONTAÑA — AMANECER · Escala senderos empinados mientras sale el sol.","action_es":"Escala senderos empinados mientras el sol se asoma tras las montañas.","action_en":"He climbs steep trails as the sun rises behind the mountains.","vo_es":"Cada sendero le costaba algo. Cada amanecer se lo devolvía.","vo_en":"Every trail cost him something. Every sunrise gave it back."},{"n":4,"slug":"MONTAJE — EXT. DESIERTO DORADO — MEDIODÍA · Camina solo bajo el sol de mediodía por un vasto desierto dorado.","action_es":"Camina solo bajo el sol del mediodía, cruzando un desierto dorado que parece no tener fin.","action_en":"He walks alone under the midday sun, crossing a golden desert that seems to have no end.","vo_es":"El desierto no perdona. Tampoco detiene a quien decide cruzarlo.","vo_en":"The desert doesn't forgive. It doesn't stop those who decide to cross it either."},{"n":5,"slug":"EXT. PUENTE DE MADERA SOBRE RÍO — DÍA · Cruza un puente angosto de madera sobre un río caudaloso.","action_es":"Cruza un puente angosto de madera sobre un río que corre con fuerza debajo de él.","action_en":"He crosses a narrow wooden bridge over a river rushing powerfully beneath him.","vo_es":"Un paso en falso, y el río decidiría por él.","vo_en":"One wrong step, and the river would decide for him."},{"n":6,"slug":"EXT. BOSQUE CON NIEBLA — MAÑANA · Continúa a través de un bosque denso cubierto de neblina matutina.","action_es":"Sigue avanzando entre un bosque denso, cubierto por la neblina de la mañana.","action_en":"He keeps moving through a dense forest, blanketed in morning mist.","vo_es":"La niebla no le mostraba el camino. Solo el siguiente paso.","vo_en":"The mist didn't show him the path. Only the next step."},{"n":7,"slug":"EXT. LLUVIA FUERTE / MONTAÑA CON NIEVE — DÍA · Una lluvia intensa cae mientras avanza; luego, viento fuerte y nieve lo desafían en la alta montaña.","action_es":"Una lluvia intensa cae sobre él sin que se detenga. Más arriba, el viento y la nieve lo desafían con toda su fuerza.","action_en":"Heavy rain falls on him without slowing him down. Higher up, wind and snow challenge him with full force.","vo_es":"Cada tormenta le preguntaba si valía la pena. Él seguía caminando como respuesta.","vo_en":"Every storm asked him if it was worth it. He kept walking as his answer."},{"n":8,"slug":"PRIMER PLANO — Tropieza, se sostiene, y sigue moviéndose sin detenerse.","action_es":"Tropieza en el hielo, se sostiene con la mano, y sigue moviéndose. Cada obstáculo cuenta, pero nada lo detiene.","action_en":"He stumbles on the ice, catches himself with his hand, and keeps moving. Every obstacle matters, but nothing stops him.","vo_es":"Se tropezó. No se quedó en el suelo.","vo_en":"He stumbled. He didn't stay on the ground."},{"n":9,"slug":"EL MOMENTO — EXT. CIMA DE LA MONTAÑA — AMANECER · Llega a la cima al amanecer; en vez de un tesoro, solo hay montañas infinitas y nubes debajo.","action_es":"Al amanecer, llega por fin a la cima. Donde se esperaba un tesoro, no hay nada —solo montañas infinitas, nubes debajo, y la primera luz del sol.","action_en":"At dawn, he finally reaches the summit. Where a treasure was expected, there is nothing — just endless mountains, clouds below, and the first light of the sun.","vo_es":"No había ningún tesoro esperándolo arriba.","vo_en":"There was no treasure waiting for him up there."},{"n":10,"slug":"PRIMER PLANO — Se quita la mochila despacio, respira profundo, cierra los ojos y sonríe en paz.","action_es":"Se quita la mochila despacio. Respira profundo. Cierra los ojos. Sonríe, en paz por primera vez en todo el viaje.","action_en":"He slowly takes off his backpack. He breathes deeply. He closes his eyes. He smiles, at peace for the first time in the entire journey.","vo_es":"Por primera vez, no necesitaba nada más.","vo_en":"For the first time, he needed nothing else."},{"n":11,"slug":"PLANO GENERAL — La cámara gira lentamente a su alrededor mientras el amanecer llena la pantalla de luz dorada.","action_es":"La cámara gira despacio a su alrededor mientras el amanecer llena la pantalla de una luz dorada cálida.","action_en":"The camera slowly circles around him as the sunrise fills the screen with warm golden light.","vo_es":"La recompensa nunca estuvo en la cima. Estuvo en cada paso para llegar ahí.","vo_en":"The reward was never at the summit. It was in every step it took to get there."},{"n":12,"slug":"CIERRE — Negro. Texto dorado elegante aparece.","action_es":"\"La recompensa más grande...\" Pausa. \"...nunca fue el destino.\" Otra pausa. \"Fue el camino.\" El logo de HeavenOnline aparece con un brillo dorado sutil.","action_en":"\"The greatest reward...\" Pause. \"...was never the destination.\" Another pause. \"It was the journey.\" The HeavenOnline logo slowly fades in with a subtle golden glow.","vo_es":"Todo viaje comienza con una decisión.","vo_en":"Every journey begins with a choice."}]},{"id":"07","title_es":"La Rueda del Destino","title_en":"The Wheel of Destiny","pillar":"anime","brand":"xsino","logline":{"es":"En una ciudadela neón que se alza en seis puertas hacia el cielo, Kairo debe cruzar cada una para llegar a la Rueda del Destino — un coloso giratorio que no premia la suerte, sino la resolución de quien se atreve a hacerla girar.","en":"In a neon citadel rising through six gates toward the sky, Kairo must cross each one to reach the Wheel of Destiny — a spinning colossus that rewards not luck, but the resolve of whoever dares to spin it."},"thesis":{"es":"La Rueda no gira para los que tienen suerte. Gira para los que no se detuvieron.","en":"The Wheel doesn't spin for the lucky. It spins for those who didn't stop."},"shots":[{"n":1,"slug":"EXT. CIUDADELA NEÓN — NOCHE · Plano general, panorámica ascendente; seis puertas apiladas se pierden en la niebla, coronadas por un resplandor lejano.","action_es":"Torres de neón magenta y cian se elevan hacia la oscuridad. Seis puertas, una sobre otra, conducen a un resplandor que nadie ha alcanzado en años.","action_en":"Towers of magenta and cyan neon rise into the dark. Six gates, stacked one above the other, lead to a glow no one has reached in years.","vo_es":"Dicen que hasta arriba gira algo que decide el destino de quien se atreve a llegar.","vo_en":"They say at the very top spins something that decides the fate of whoever dares to reach it."},{"n":2,"slug":"PLANO MEDIO — Kairo, de pie ante la Primera Puerta, capa raída, ojos brillando cian bajo la capucha.","action_es":"Kairo mira hacia arriba. No es el más fuerte de los que lo han intentado. Pero es el único que sigue de pie.","action_en":"Kairo looks up. He's not the strongest of those who've tried. But he's the only one still standing.","vo_es":"Otros llegaron más lejos. Ninguno llegó completo.","vo_en":"Others made it further. None made it whole."},{"n":3,"slug":"EXT. PUERTA DE BRONCE — NOCHE · Plano contrapicado; la puerta se abre entre chispas y engranajes de neón.","action_es":"La Puerta de Bronce reconoce su paso y se abre con un chirrido metálico. Kairo entra sin mirar atrás.","action_en":"The Bronze Gate recognizes his stride and grinds open. Kairo walks in without looking back.","vo_es":"La primera puerta no pide fuerza. Pide que no dudes.","vo_en":"The first gate doesn't ask for strength. It asks that you don't hesitate."},{"n":4,"slug":"INT. SALA DE LA RUEDA — SOMBRA · Plano medio; Vega, la Guardiana de la Rueda, observa desde las alturas entre listones de luz violeta y dorada.","action_es":"Vega, la Guardiana de la Rueda, lo observa desde lejos. \"Seis puertas. Una Rueda. La Rueda no juzga la suerte de nadie — juzga si de verdad quieren llegar.\"","action_en":"Vega, the Wheel Keeper, watches from afar. \"Six gates. One Wheel. The Wheel judges no one's luck — it judges whether they truly want to arrive.\"","vo_es":"Seis puertas. Una Rueda. Y una sola pregunta detrás de todas.","vo_en":"Six gates. One Wheel. And a single question behind all of them."},{"n":5,"slug":"MONTAJE RÁPIDO — Planos cortos encadenados; Kairo cruza la Puerta de Plata, la de Zafiro y la de Platino, cada vez más golpeado, cada vez más firme.","action_es":"Plata. Zafiro. Platino. Cada puerta le cuesta más. Cada puerta lo deja más cerca.","action_en":"Silver. Sapphire. Platinum. Each gate costs him more. Each gate leaves him closer.","vo_es":"No subía porque tuviera suerte. Subía porque no soltaba.","vo_en":"He wasn't climbing because he was lucky. He was climbing because he didn't let go."},{"n":6,"slug":"EXT. PUERTA DE DIAMANTE — NOCHE · Plano general; Nyx, la Guardiana rival, bloquea el paso entre columnas de neón magenta.","action_es":"Nyx aparece entre destellos magenta, sonrisa filosa. \"¿Tú? Los que llegan hasta aquí ya perdieron algo que no van a recuperar.\"","action_en":"Nyx appears between magenta flares, a sharp smile. \"You? Everyone who makes it this far has already lost something they won't get back.\"","vo_es":"Nyx no cierra la puerta con fuerza. La cierra con dudas.","vo_en":"Nyx doesn't close the gate with force. She closes it with doubt."},{"n":7,"slug":"PRIMER PLANO — Kairo sostiene la mirada de Nyx sin retroceder; su mano cian se cierra en un puño firme.","action_es":"Kairo no discute. Solo da un paso más. \"Puede ser. Pero todavía estoy aquí.\"","action_en":"Kairo doesn't argue. He just takes one more step. \"Maybe. But I'm still here.\"","vo_es":"A veces ganar la puerta no es vencer al guardián. Es no darle la razón.","vo_en":"Sometimes beating the gate isn't defeating the guardian. It's refusing to agree with them."},{"n":8,"slug":"PLANO CONTRAPICADO — Nyx se aparta, entre respeto forzado y desafío pendiente; la Puerta de Diamante se abre.","action_es":"Nyx se hace a un lado, apenas. \"Ve. La Rueda decide lo que yo no puedo.\" La última puerta se abre ante él.","action_en":"Nyx steps aside, barely. \"Go. The Wheel decides what I can't.\" The final gate opens before him.","vo_es":"La última puerta no lo detuvo. Solo lo dejó pasar, con la duda todavía encendida.","vo_en":"The last gate didn't stop him. It just let him through, doubt still burning."},{"n":9,"slug":"INT. CÁMARA DE LA RUEDA — NOCHE · Plano general; la Rueda del Destino, un coloso giratorio de neón, llena la sala con un giro lento e inmenso.","action_es":"Ahí está: la Rueda del Destino, girando despacio, colosal, silenciosa. Kairo la mira como quien mira, por fin, la pregunta completa.","action_en":"There it is: the Wheel of Destiny, spinning slowly, colossal, silent. Kairo looks at it like someone finally seeing the whole question.","vo_es":"Seis puertas para llegar a una sola pregunta.","vo_en":"Six gates, to reach a single question."},{"n":10,"slug":"PRIMER PLANO — La mano de Kairo se acerca al borde de la Rueda; Fortuna, silueta de luz iridiscente, emerge del giro.","action_es":"Fortuna, el espíritu de la Rueda, se asoma entre destellos. \"No pregunto si tienes suerte. Pregunto si estás listo para lo que venga.\"","action_en":"Fortuna, the spirit of the Wheel, emerges between flares. \"I don't ask if you're lucky. I ask if you're ready for whatever comes.\"","vo_es":"Fortuna no promete un premio. Promete una respuesta.","vo_en":"Fortuna doesn't promise a prize. She promises an answer."},{"n":11,"slug":"EL MOMENTO — Congelación de tiempo. La Rueda se detiene a media vuelta; un único destello dorado recorre sus bordes de neón.","action_es":"El tiempo se detiene. El magenta y el cian se apagan. Solo el borde de la Rueda arde en oro, suspendido, indeciso.","action_en":"Time stops. The magenta and cyan fade. Only the Wheel's rim burns gold, suspended, undecided.","vo_es":"La suerte no estaba en la Rueda. Estaba en las seis puertas que ya había cruzado.","vo_en":"The luck was never in the Wheel. It was in the six gates he'd already crossed."},{"n":12,"slug":"PLANO GENERAL — La Rueda retoma su giro más allá del congelamiento; Kairo se mantiene firme, listo, sin saber aún el resultado.","action_es":"La Rueda retoma su giro. Kairo no aparta la mirada. No sabe qué va a marcar. Sabe que ya cruzó lo que tenía que cruzar.","action_en":"The Wheel resumes its spin. Kairo doesn't look away. He doesn't know what it will land on. He knows he's already crossed what he had to cross.","vo_es":"Todavía no sabía el resultado. Pero ya no era el mismo que entró por la primera puerta.","vo_en":"He still didn't know the outcome. But he was no longer the one who walked through the first gate."},{"n":13,"slug":"CIERRE — Negro. Aparece la firma XSINO en oro.","action_es":"XSINO — La suerte empieza en la próxima decisión.","action_en":"XSINO — Luck begins with the next decision.","vo_es":"Seis puertas ya se abrieron. ¿Cuál cruzarías tú primero?","vo_en":"Six gates have already opened. Which one would you cross first?"}]}],"bible":{"brand":[{"es":"La Tesis","en":"The Thesis","pairs":[{"es":"La suerte empieza en la próxima decisión.","en":"Luck begins with the next decision.","proposal":false},{"es":"La suerte no es solo dinero. Es esperanza, es tiempo, es amor, es coraje, y es una segunda oportunidad.","en":"Luck is not only money. It is hope, it is timing, it is love, it is courage, and it is a second chance.","proposal":false},{"es":"XSINO no vende premios; cuenta el instante humano justo antes de que la vida cambie —el segundo en que alguien decide seguir intentando.","en":"XSINO does not sell prizes; it tells the human instant right before a life changes — the second when someone decides to keep going.","proposal":false},{"es":"Cada pieza de contenido termina en la misma promesa silenciosa: tu próxima decisión también puede cambiarlo todo.","en":"Every piece of content lands on the same quiet promise: your next decision can change everything too.","proposal":false}]},{"es":"A Quién le Hablamos","en":"Who We Speak To","pairs":[{"es":"Audiencia primaria: adultos de 21+ en Latinoamérica, con foco inicial en Guatemala y el mercado hispanohablante, que consumen video corto (TikTok, Reels, Shorts).","en":"Primary audience: adults 21+ across Latin America, with an initial focus on Guatemala and the Spanish-speaking market, who consume short-form video (TikTok, Reels, Shorts).","proposal":false},{"es":"Audiencia secundaria: espectadores fuera del segmento de casino o gaming, alcanzados por temas universales —destino, familia, amor y transformación.","en":"Secondary audience: viewers outside the casino or gaming segment, reached through universal themes — destiny, family, love, and transformation.","proposal":false},{"es":"Tono emocional antes que publicidad de bonos. Entretenemos primero; la marca se recuerda por cómo hizo sentir a la persona.","en":"Emotional tone before bonus advertising. We entertain first; the brand is remembered for how it made the person feel.","proposal":false}]},{"es":"Reglas de Marca","en":"Brand Rules","pairs":[{"es":"1. Nunca prometemos ganar. Mostramos esperanza, decisión y segundas oportunidades —no resultados garantizados.","en":"1. We never promise winning. We show hope, decision, and second chances — not guaranteed outcomes.","proposal":false},{"es":"2. La marca aparece al final, no al principio. Primero la historia; el logo de XSINO cierra como una firma, no como un anuncio.","en":"2. The brand appears at the end, not the start. Story first; the XSINO logo closes like a signature, not an ad.","proposal":false},{"es":"3. Juego responsable siempre. Todo contenido dirigido a 21+; incluir aviso de juego responsable cuando la plataforma lo exija.","en":"3. Responsible gaming, always. All content is 21+; include a responsible-gaming notice wherever the platform requires it.","proposal":false},{"es":"4. Un momento, una emoción. Cada video persigue un solo sentimiento y un solo giro —no lo diluimos.","en":"4. One moment, one emotion. Each video chases a single feeling and a single turn — we do not dilute it.","proposal":false},{"es":"5. El oro es sagrado. El dorado de XSINO se raciona: aparece en el instante de la suerte, no en todo el cuadro.","en":"5. Gold is sacred. The XSINO gold is rationed: it appears at the instant of luck, not across the whole frame.","proposal":false}]},{"es":"El Motor de Contenido","en":"The Content Engine","pairs":[{"es":"XSINO produce en cuatro pilares narrativos, cada uno con su elenco, su paleta y su formato. Un mismo motor de IA los recrea a escala y en dos idiomas (español e inglés).","en":"XSINO produces across four narrative pillars, each with its own cast, palette, and format. A single AI engine recreates them at scale in two languages (Spanish and English).","proposal":false},{"es":"Flujo: guion → guion gráfico (storyboard) → fotogramas clave (keyframes) → clips → montaje. El texto y el diseño se fijan una vez; la generación se repite.","en":"Flow: script → storyboard → keyframes → clips → edit. Text and design are locked once; generation is repeated.","proposal":false},{"es":"La ventaja de XSINO: temas universales que cruzan mercados, compatibilidad total con video vertical corto, y escalabilidad de producción con IA.","en":"XSINO's advantage: universal themes that cross markets, full compatibility with short vertical video, and AI production scalability.","proposal":false}]},{"es":"Plataformas","en":"Platforms","pairs":[{"es":"TikTok — campo de pruebas principal. Aquí se testean ganchos (primeros 3 segundos) y formatos de participación (encuestas, \"¿tú qué elegirías?\").","en":"TikTok — primary testing ground. Here we test hooks (first 3 seconds) and participation formats (polls, \"what would you choose?\").","proposal":false},{"es":"Instagram — versión premium y pulida. Se prioriza la cinematografía y el acabado; los Reels con mejor retención pasan aquí.","en":"Instagram — premium, polished version. Cinematography and finish are prioritized; the best-retaining Reels graduate here.","proposal":false},{"es":"Facebook — subtítulos largos y resonancia emocional con audiencias mayores. La historia se cuenta también en el copy.","en":"Facebook — long captions and emotional resonance with older audiences. The story is also told in the copy.","proposal":false}]},{"es":"Cómo Medimos","en":"How We Measure","pairs":[{"es":"Retención más allá del momento clave: ¿el espectador se queda hasta el giro (la moneda, la voz, el cruce)?","en":"Retention past the key moment: does the viewer stay through the turn (the coin, the voice, the crossing)?","proposal":false},{"es":"Tasa de finalización, y guardados/compartidos como señal de resonancia (pesan más que los likes).","en":"Completion rate, and saves/shares as the resonance signal (they matter more than likes).","proposal":false},{"es":"Sentimiento en comentarios, y recuerdo de marca medido con variantes del cierre de logo.","en":"Comment sentiment, and brand recall measured through variations of the logo reveal.","proposal":false}]},{"es":"Estado","en":"Status","pairs":[{"es":"Elenco, backdrops y guiones de esta biblia son una primera propuesta creativa mientras llega la línea narrativa oficial de los otros equipos. Todo lo marcado como PROPUESTA se vuelve canon solo tras aprobación.","en":"The cast, backdrops, and scripts in this bible are a first creative proposal while the official storyline from the other teams arrives. Everything flagged PROPOSAL becomes canon only after sign-off.","proposal":true}]}],"official":[{"es":"Dos Marcas","en":"Two Brands","pairs":[{"es":"Lucifer Gaming opera dos marcas hermanas. XSINO — casino cyberpunk (México/LatAm). HeavenOnline — marca hermana, tono más cálido y romántico/inspirador. El motor de contenido sirve a ambas.","en":"Lucifer Gaming runs two sibling brands. XSINO — cyberpunk casino (Mexico/LatAm). HeavenOnline — sibling brand, warmer, more romantic/inspirational tone. The content engine serves both.","proposal":false}]},{"es":"Identidad Visual XSINO","en":"XSINO Visual Identity","pairs":[{"es":"Estilo: cyberpunk. Predominan morado, rosa/magenta y azul claro/cian, con glows de neón; se pueden usar otros colores (verde, naranja) según el arte.","en":"Style: cyberpunk. Purple, pink/magenta, and light-blue/cyan predominate, with neon glows; other colors (green, orange) allowed per the art.","proposal":false},{"es":"Tipografías: display techy — Venus Rising, Ethnocentric, Conthrax Semi Bold, Spy Agency; logo — Akira Expanded, Helvetica Neue Cond. Italic; cuerpo — Montserrat (Bold/Regular).","en":"Fonts: techy display — Venus Rising, Ethnocentric, Conthrax Semi Bold, Spy Agency; logo — Akira Expanded, Helvetica Neue Cond. Italic; body — Montserrat (Bold/Regular).","proposal":false},{"es":"Logo: la «X» en degradado (blanco→magenta→cian) + «SINO» / «SINO.IO» + «CASINO»; marca «X» suelta; versiones negativas en negro. Archivos en Logos and assets/.","en":"Logo: the gradient \"X\" (white→magenta→cyan) + \"SINO\" / \"SINO.IO\" + \"CASINO\"; standalone \"X\" mark; black negative versions. Files in Logos and assets/.","proposal":false},{"es":"Elementos oficiales: 4 personajes anime (héroe pelo morado/verde con audífonos; chica pelo verde; chica bob oscuro «gamer» con kanji; chica orejas-de-gato rosa), ciudad neón, mesa de casino neón, puertas/bóvedas brillantes, monedas-token «X» (cromada) y «S» (rosa).","en":"Official elements: 4 anime characters (purple/green-haired hero with headphones; green-haired girl; dark-bob \"gamer\" girl with kanji; pink cat-ear girl), neon city, neon casino table, glowing gates/vaults, coin-tokens \"X\" (chrome) and \"S\" (pink).","proposal":false}]},{"es":"Identidad HeavenOnline","en":"HeavenOnline Identity","pairs":[{"es":"HeavenOnline (HeavenOnline.io) — identidad OPUESTA a XSINO: lujo celestial, negro + oro + blanco/plata, tipografía serif elegante, imaginería de ángel/alas. Tono cálido, romántico e inspirador; producto: la app HeavenOnline. Cierre de logo con luz dorada. Logos blanco/negro/color en Logos and assets/.","en":"HeavenOnline (HeavenOnline.io) — identity OPPOSITE to XSINO: celestial luxury, black + gold + white/silver, elegant serif type, angel/wings imagery. Warm, romantic, inspirational tone; product: the HeavenOnline app. Logo close with golden light. White/black/color logos in Logos and assets/.","proposal":false}]},{"es":"Formato de Video","en":"Video Format","pairs":[{"es":"Todos los clips: vertical 9:16, 15–40 segundos. Cine ultra-realista, calidad Hollywood, 4K, storytelling emocional. El oro se reserva para el momento clave y el cierre de logo.","en":"All clips: vertical 9:16, 15–40 seconds. Ultra-realistic cinema, Hollywood quality, 4K, emotional storytelling. Gold is reserved for the key moment and the logo close.","proposal":false}]},{"es":"Las 6 Películas Oficiales","en":"The 6 Official Films","pairs":[{"es":"XSINO: (1) La Moneda del Destino — mecánico 25 años, moneda dorada mágica que congela el tiempo, abre la app XSINO. (2) El Abuelo y su Nieta — «¿ganaste la lotería?», la suerte era la familia. (3) Cada Día una Oportunidad — resiliencia, rechazos que no lo detienen.","en":"XSINO: (1) The Coin of Destiny — 25-yo mechanic, magical golden coin that freezes time, opens the XSINO app. (2) The Grandfather and His Granddaughter — \"did you win the lottery?\", luck was family. (3) Every Day a New Opportunity — resilience, rejections that don't stop him.","proposal":false},{"es":"HeavenOnline: (4) Dos Extraños — vidas paralelas, la app HeavenOnline, tazas mostaza + chaqueta azul marino, se cruzan al final. (5) El Sueño — niño futbolista, montaje de entrenamiento, túnel del estadio (nunca se ve la cara). (6) El Viaje — viajero solitario, la cima no tenía tesoro, el premio era el camino.","en":"HeavenOnline: (4) Two Strangers — parallel lives, the HeavenOnline app, mustard mugs + navy jacket, they cross at the end. (5) The Dream — boy footballer, training montage, stadium tunnel (face never shown). (6) The Journey — lone traveler, the summit held no treasure, the reward was the journey.","proposal":false},{"es":"Frases de cierre canónicas (exactas): «You can't change the past... But you can always choose what comes next.» / «Luck favors those who never stop trying.» / «My greatest luck... has always been you.» / «Some of life's best surprises... happen when paths cross.» / «Every great story begins with a dream.» / «The greatest reward... was never the destination. It was the journey.»","en":"Canonical closing lines (exact): \"You can't change the past... But you can always choose what comes next.\" / \"Luck favors those who never stop trying.\" / \"My greatest luck... has always been you.\" / \"Some of life's best surprises... happen when paths cross.\" / \"Every great story begins with a dream.\" / \"The greatest reward... was never the destination. It was the journey.\"","proposal":false}]}],"pillars":[{"es":"Historias que Inspiran","en":"Stories That Inspire","pairs":[{"es":"Esperanza y resiliencia. Gente común que persevera y se transforma; el momento en que una decisión pequeña reescribe una vida.","en":"Hope and resilience. Ordinary people who persevere and transform; the moment a small decision rewrites a life.","proposal":false},{"es":"Historias base: \"La Moneda del Destino\" y \"El Abuelo y su Nieta\".","en":"Anchor stories: \"The Coin of Destiny\" and \"The Grandfather and His Granddaughter.\"","proposal":false},{"es":"Formato: realismo cinematográfico cálido, 30–60s, con una congelación de tiempo en el instante de la decisión.","en":"Format: warm cinematic realism, 30–60s, with a time-freeze on the instant of the decision.","proposal":false}]},{"es":"Amores Imposibles","en":"Impossible Love Stories","pairs":[{"es":"Romance y destino. Contenido pensado para alcanzar audiencias fuera del segmento de casino o gaming.","en":"Romance and fate. Content designed to reach audiences beyond the casino or gaming segment.","proposal":false},{"es":"Historia base: \"Dos Extraños\" — montaje paralelo: la misma canción, el mismo color, el mismo café, y un cruce final.","en":"Anchor story: \"Two Strangers\" — parallel editing: the same song, the same color, the same coffee, and a final crossing.","proposal":false},{"es":"Formato: romance fílmico, pantalla dividida o corte paralelo, paleta compartida ámbar y verde-azulado.","en":"Format: filmic romance, split-screen or parallel cut, a shared amber-and-teal palette.","proposal":false}]},{"es":"Universo Anime XSINO","en":"XSINO Anime Universe","pairs":[{"es":"Aventura fantástica que conecta las mecánicas del juego —niveles, puertas VIP, retos, recompensas— con un mundo de ficción reconocible.","en":"Fantasy adventure connecting the game's mechanics — levels, VIP gates, challenges, rewards — to a recognizable fictional world.","proposal":false},{"es":"Historia base: \"La Rueda del Destino\" (shonen). El universo visual más escalable y el vínculo más fuerte con el producto.","en":"Anchor story: \"The Wheel of Destiny\" (shonen). The most scalable visual universe and the strongest tie to the product.","proposal":false},{"es":"Formato: anime shonen + cyberpunk, neón sobre negro, la Rueda del Destino como coloso giratorio; niveles VIP recurrentes.","en":"Format: shonen anime + cyberpunk, neon over black, the Wheel of Destiny as a spinning colossus; recurring VIP levels.","proposal":false}]},{"es":"¿Y Si...?","en":"What If...?","pairs":[{"es":"Curiosidad de giro rápido. Episodios repetibles de menos de 30 segundos, guiados por voz en off, fáciles de convertir en serie.","en":"Quick-twist curiosity. Repeatable episodes under 30 seconds, voiceover-driven, easy to turn into a series.","proposal":false},{"es":"Historia base: \"¿Y Si la Suerte Tuviera Voz?\" — la Suerte personificada habla al espectador y le propone una elección.","en":"Anchor story: \"What If Luck Had a Voice?\" — Luck personified speaks to the viewer and offers a choice.","proposal":false},{"es":"Formato: gráfico y minimalista, alto contraste, oro sobre negro; termina en pregunta directa a la cámara para provocar comentarios.","en":"Format: graphic and minimal, high contrast, gold over black; ends on a direct question to camera to drive comments.","proposal":false}]}],"visual":[{"es":"Paleta Maestra","en":"Master Palette","pairs":[{"es":"Noche XSINO (fondo): negro azulado profundo #0B0E17. Oro XSINO (acento sagrado): #E8B84B, con brillo #F6D98A. El oro se raciona al instante de la suerte.","en":"XSINO Night (background): deep blue-black #0B0E17. XSINO Gold (sacred accent): #E8B84B, with a highlight of #F6D98A. Gold is rationed to the instant of luck.","proposal":false},{"es":"Neutros: marfil #EDE6D4 para texto, gris humo #948F82 para apoyo. El rojo brasa #C0453B se reserva para tensión y riesgo.","en":"Neutrals: ivory #EDE6D4 for text, smoke grey #948F82 for support. Ember red #C0453B is reserved for tension and risk.","proposal":false}]},{"es":"Acento por Pilar","en":"Accent per Pillar","pairs":[{"es":"Historias que Inspiran — hora dorada, ámbar cálido #D9A441; realismo tangible, grano de película suave.","en":"Stories That Inspire — golden hour, warm amber #D9A441; tangible realism, soft film grain.","proposal":false},{"es":"Amores Imposibles — ámbar #E0A46A y verde-azulado #4C8C86 compartidos entre los dos amantes; luz de ventana y lluvia.","en":"Impossible Love Stories — amber #E0A46A and teal #4C8C86 shared between the two lovers; window light and rain.","proposal":false},{"es":"Universo Anime XSINO — neón: magenta #E24D9C y cian #34C6E0 sobre negro, con oro para la Rueda; estética shonen-cyberpunk.","en":"XSINO Anime Universe — neon: magenta #E24D9C and cyan #34C6E0 over black, with gold for the Wheel; shonen-cyberpunk aesthetic.","proposal":false},{"es":"¿Y Si...? — oro puro sobre negro, gráfico y de alto contraste; un solo foco de luz sobre la Suerte.","en":"What If...? — pure gold over black, graphic and high-contrast; a single spotlight on Luck.","proposal":false}]},{"es":"Reglas de Encuadre","en":"Framing Rules","pairs":[{"es":"Vertical 9:16 nativo para las plataformas; master 16:9 solo cuando se pida versión horizontal.","en":"Native vertical 9:16 for the platforms; 16:9 master only when a horizontal cut is requested.","proposal":false},{"es":"El momento clave (la moneda, la voz, el cruce, el giro de la Rueda) siempre recibe una congelación o cámara lenta y el único destello de oro.","en":"The key moment (the coin, the voice, the crossing, the Wheel's turn) always gets a freeze or slow-motion and the single flash of gold.","proposal":false},{"es":"Cierre de marca: el logo XSINO aparece como firma en los últimos 1–2 segundos sobre negro, nunca antes.","en":"Brand close: the XSINO logo appears as a signature in the final 1–2 seconds over black, never before.","proposal":false}]},{"es":"Motivos Recurrentes","en":"Recurring Motifs","pairs":[{"es":"La moneda que gira en el aire (decisión). El hilo de luz dorada (destino que conecta a las personas). La Rueda (el producto en forma de mito).","en":"The coin spinning in the air (decision). The thread of golden light (fate connecting people). The Wheel (the product as myth).","proposal":false},{"es":"La Suerte personificada (La Suerte) es el hilo conductor de la marca: puede aparecer como voz, como silueta luminosa, o como personaje anime según el pilar.","en":"Luck personified (La Suerte) is the brand's throughline: it can appear as a voice, a luminous silhouette, or an anime character depending on the pillar.","proposal":false}]}],"pipeline":[{"es":"Principio","en":"Principle","pairs":[{"es":"El arte primero, el video al final. El texto (guion) y el diseño (fichas de personaje, paletas) se fijan una vez; la generación se repite a escala.","en":"Art first, video last. Text (script) and design (character sheets, palettes) are locked once; generation is repeated at scale.","proposal":false},{"es":"La generación de video es un paso manual y aprobado —el motor produce el kit listo para generar; la ejecución de video la corre el equipo, no se dispara sola.","en":"Video generation is a manual, approved step — the engine produces the ready-to-generate kit; video execution is run by the team, it is not auto-fired.","proposal":false}]},{"es":"Las Seis Etapas","en":"The Six Stages","pairs":[{"es":"1. Guion — el guion literario/gráfico por historia (screenplay.md), bilingüe, tiro por tiro con cámara, acción y voz en off.","en":"1. Script — the screenplay per story (screenplay.md), bilingual, shot-by-shot with camera, action, and voiceover.","proposal":false},{"es":"2. Anclas de identidad — una ficha de personaje (front/side/back/expresión/acción) por cada personaje, generada una vez y reutilizada como referencia.","en":"2. Identity anchors — one character sheet (front/side/back/expression/action) per character, generated once and reused as a reference.","proposal":false},{"es":"3. Backdrops — las láminas de fondo (plates) por localización y pilar, generadas desde la base de prompts.","en":"3. Backdrops — background plates per location and pillar, generated from the prompt database.","proposal":false},{"es":"4. Keyframes — un fotograma por tiro (shot), incrustando la referencia de identidad de cada personaje en cuadro.","en":"4. Keyframes — one frame per shot, embedding each in-frame character's identity reference.","proposal":false},{"es":"5. Revisión — el equipo revisa todo el arte antes de cualquier video.","en":"5. Review — the team reviews all art before any video.","proposal":false},{"es":"6. Video — clips i2v (imagen-a-video) desde el keyframe aprobado, una línea de movimiento simple por tiro; montaje final con voz y música.","en":"6. Video — i2v (image-to-video) clips from the approved keyframe, one simple motion line per shot; final edit with voice and music.","proposal":false}]},{"es":"El Motor Guion→Kit","en":"The Script→Kit Engine","pairs":[{"es":"El motor (carpeta 10_Pipeline) recibe un screenplay.md y produce: un shot-list en JSON, un pack de prompts de imagen y de video por tiro, un manifiesto, y un plan de montaje.","en":"The engine (folder 10_Pipeline) ingests a screenplay.md and outputs: a shot-list JSON, an image and video prompt pack per shot, a manifest, and an edit plan.","proposal":false},{"es":"Lanes de generación (según aprobación y costo): Pollinations (gratis, para concepto/backdrops), Flow/Nano Banana 2 y Higgsfield (identidad bloqueada, solo con aprobación), y video i2v manual.","en":"Generation lanes (by approval and cost): Pollinations (free, for concept/backdrops), Flow/Nano Banana 2 and Higgsfield (identity-locked, approval only), and manual i2v video.","proposal":false}]}]}};
